{
  "name": "SerDes Design for Kids",
  "description": "An interactive, fun educational tool for middle schoolers to learn about high-speed data transmission (SerDes), PAM signaling, and signal integrity using real-time simulation and AI tutoring."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum PamType {
  PAM2 = 'PAM2',
  PAM4 = 'PAM4',
}

export interface SimulationParams {
  pamType: PamType;
  dataRateGbps: number;
  channelResponse: number[]; // H[n] impulse response
  equalizerTaps: number[]; // H_eq[n] FFE taps
  noiseLevel: number; // Standard deviation of Gaussian noise
  useEqualizer: boolean;
}

export interface SimulationResult {
  txSymbols: number[];
  rxSignalRaw: number[]; // After channel + noise
  rxSignalEq: number[]; // After equalizer
  bits: number[];
  ber: number;
}

export interface BlockDefinition {
  id: string;
  name: string;
  description: string;
  emoji: string;
  type: 'generator' | 'tx' | 'channel' | 'rx' | 'analysis';
}

import { PamType, SimulationParams, BlockDefinition } from './types';

export const DEFAULT_PARAMS: SimulationParams = {
  pamType: PamType.PAM2,
  dataRateGbps: 10,
  channelResponse: [0.9, 0.3, 0.1, 0.05, 0.0], // Default slightly lossy channel
  equalizerTaps: [0.0, 1.0, 0.0], // Pass-through initially
  noiseLevel: 0.05,
  useEqualizer: false,
};

export const BLOCKS: BlockDefinition[] = [
  { id: 'gen', name: 'Data Factory', emoji: '🏭', description: 'Generates random 1s and 0s (Bits)!', type: 'generator' },
  { id: 'tx', name: 'Launcher (TX)', emoji: '🚀', description: 'Converts bits into voltage levels (Symbols).', type: 'tx' },
  { id: 'channel', name: 'The Canyon (Channel)', emoji: '🏜️', description: 'The wire or air where signal gets distorted and noisy.', type: 'channel' },
  { id: 'rx_eq', name: 'Magic Glasses (FFE)', emoji: '👓', description: 'Tries to fix the messy signal using math.', type: 'rx' },
  { id: 'rx_slicer', name: 'Decider (RX)', emoji: '🧠', description: 'Guesses what the original bit was.', type: 'rx' },
];

export const SYSTEM_INSTRUCTION = `You are Professor Sparky, a world-class electronics engineer who explains complex concepts to middle school students. 
Use funny analogies (like pizza delivery, traffic jams, shouting across canyons). 
Keep explanations short (under 3 sentences), encouraging, and use emojis. 
Never use complex calculus equations. Focus on intuition.
When explaining 'Channel', talk about how wires are like messy hallways.
When explaining 'Equalizer', talk about how glasses correct blurry vision.
When explaining 'PAM', compare it to using different colored flags instead of just black and white.`;

import { PamType, SimulationParams, SimulationResult } from '../types';

// Helper: Gaussian Random
const randn_bm = (): number => {
  let u = 0, v = 0;
  while (u === 0) u = Math.random();
  while (v === 0) v = Math.random();
  return Math.sqrt(-2.0 * Math.log(u)) * Math.cos(2.0 * Math.PI * v);
};

// Helper: Convolution
const convolve = (signal: number[], kernel: number[]): number[] => {
  const outputLength = signal.length + kernel.length - 1;
  const output = new Float32Array(outputLength);
  for (let i = 0; i < signal.length; i++) {
    for (let j = 0; j < kernel.length; j++) {
      output[i + j] += signal[i] * kernel[j];
    }
  }
  return Array.from(output); // Keep full tail for simplicity in this demo
};

export const runSimulation = (params: SimulationParams, numBits: number = 2000): SimulationResult => {
  const { pamType, channelResponse, equalizerTaps, noiseLevel, useEqualizer } = params;

  // 1. Generate Bits
  const bits: number[] = [];
  for (let i = 0; i < numBits; i++) {
    bits.push(Math.random() > 0.5 ? 1 : 0);
  }

  // 2. Map to Symbols (TX)
  let txSymbols: number[] = [];
  if (pamType === PamType.PAM2) {
    // NRZ: 0 -> -1, 1 -> +1
    txSymbols = bits.map(b => (b === 0 ? -1 : 1));
  } else {
    // PAM4: 00 -> -3, 01 -> -1, 10 -> +1, 11 -> +3
    // We need even number of bits
    if (bits.length % 2 !== 0) bits.pop();
    for (let i = 0; i < bits.length; i += 2) {
      const val = (bits[i] << 1) | bits[i + 1];
      // Map 0->-3, 1->-1, 2->1, 3->3 (Gray coding is better but Linear is easier for kids to grasp math)
      // Let's stick to simple linear mapping for simplicity:
      // 00 (0) -> -3
      // 01 (1) -> -1
      // 10 (2) -> +1
      // 11 (3) -> +3
      if (val === 0) txSymbols.push(-3);
      else if (val === 1) txSymbols.push(-1);
      else if (val === 2) txSymbols.push(1);
      else if (val === 3) txSymbols.push(3);
    }
  }

  // 3. Channel Convolution
  let channelOut = convolve(txSymbols, channelResponse);

  // 4. Add Noise
  // We trim the convolution tail to match symbol length roughly for visualization, 
  // but in reality we keep it. For the "Eye", we need the continuous stream.
  // Let's just noise up the whole output.
  const rxSignalRaw = channelOut.map(v => v + randn_bm() * noiseLevel);

  // 5. Equalizer (FFE)
  let rxSignalEq: number[] = [];
  if (useEqualizer) {
    rxSignalEq = convolve(rxSignalRaw, equalizerTaps);
    // Equalizer introduces delay (latency). 
    // Usually we align signals for BER check.
    // For visual simplicity, we'll just present the convolved output.
  } else {
    rxSignalEq = [...rxSignalRaw];
  }

  // 6. Slicer / BER Checker (Simplified)
  // We need to account for delay to check BER. 
  // Delay ~= Channel Peak Index + Equalizer Peak Index
  const findPeakIndex = (arr: number[]) => arr.indexOf(Math.max(...arr));
  const channelDelay = findPeakIndex(channelResponse);
  const eqDelay = useEqualizer ? findPeakIndex(equalizerTaps) : 0;
  const totalDelay = channelDelay + eqDelay;

  let errors = 0;
  let comparedCount = 0;

  // Simple Slicer Logic
  for (let i = 0; i < txSymbols.length; i++) {
    const rxIdx = i + totalDelay;
    if (rxIdx >= rxSignalEq.length) break;

    const val = rxSignalEq[rxIdx];
    let decided = 0;

    if (pamType === PamType.PAM2) {
      decided = val >= 0 ? 1 : -1;
    } else {
      // PAM4 Thresholds: -2, 0, 2
      if (val < -2) decided = -3;
      else if (val < 0) decided = -1;
      else if (val < 2) decided = 1;
      else decided = 3;
    }

    if (decided !== txSymbols[i]) {
      errors++;
    }
    comparedCount++;
  }

  const ber = comparedCount > 0 ? errors / comparedCount : 0;

  return {
    txSymbols,
    rxSignalRaw, // For viewing signal before EQ
    rxSignalEq,  // For viewing signal after EQ (and Eye Diagram)
    bits,
    ber
  };
};

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";

export const askProfessorSparky = async (context: string, question: string): Promise<string> => {
  if (!process.env.API_KEY) {
    return "Professor Sparky is on a coffee break (Missing API Key).";
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Context of the app state: ${context}\n\nUser Question: ${question}`,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      },
    });

    return response.text || "I'm scratching my head on that one!";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Oops! My radio signal is breaking up. Try again later.";
  }
};

import React, { useRef, useEffect } from 'react';
import { PamType } from '../types';

interface EyeDiagramProps {
  data: number[];
  pamType: PamType;
  width?: number;
  height?: number;
  title: string;
}

const EyeDiagram: React.FC<EyeDiagramProps> = ({ data, pamType, width = 400, height = 300, title }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Clear background
    ctx.fillStyle = '#0f172a'; // Slate 900
    ctx.fillRect(0, 0, width, height);

    // Draw Grid
    ctx.strokeStyle = '#334155';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(0, height / 2);
    ctx.lineTo(width, height / 2); // Center horizontal
    ctx.moveTo(width / 2, 0);
    ctx.lineTo(width / 2, height); // Center vertical
    ctx.stroke();

    // Setup scaling
    // We render 2 UI (Unit Intervals) per trace to show the "Eye" crossing
    // Samples per UI. In our simulation, we only produce 1 sample per symbol (ideal sampling point).
    // To draw a proper eye diagram, we usually need oversampled data (e.g., 16 samples per UI).
    // However, our `dsp.ts` produces discrete symbols. 
    // To make it look like a real SerDes eye, we can interpolate.

    // Simulating analog waveform via interpolation (Catmull-Rom or simple Cubic)
    // We will slice the data into 2-symbol chunks (plus neighbors for interpolation)

    const samplesPerUI = 32; 
    const traceWidth = width; 

    // Vertical scale
    const maxY = pamType === PamType.PAM4 ? 4.5 : 2.0; 
    const scaleY = (height / 2) / maxY;
    const offsetY = height / 2;

    ctx.strokeStyle = '#4ade80'; // Green-400
    ctx.globalAlpha = 0.15; // Transparency for "heat map" effect
    ctx.lineWidth = 2;

    // We iterate through the symbols and draw curves
    // p0, p1, p2, p3 are consecutive symbols. We draw from p1 to p2.
    for (let i = 1; i < data.length - 2; i++) {
        const p0 = data[i-1];
        const p1 = data[i];
        const p2 = data[i+1];
        const p3 = data[i+2];

        ctx.beginPath();
        for (let t = 0; t <= samplesPerUI * 2; t++) {
            // t goes from 0 to 2*samplesPerUI (showing 2 UIs width centered)
            // But we actually want to overlay all transitions.
            // Let's just draw the segment p1 -> p2 centered. 
            // Better: Draw a 2-UI window. 
            // To effectively draw an eye, we overlay segments of length 2*UI.

            // Parametric t for Catmull-Rom spline between p1 and p2 is 0..1
            // We map x coordinate to width.

            // Wait, standard eye diagram folds time.
            // Let's draw 2 UI duration.
            // We need to interpolate across p0..p3 to get a smooth curve for the p1-p2 interval.
            // But an eye diagram typically shows the transition. 
            // Let's draw the transition centered at width/2.

            // Strategy: 
            // 1. Interpolate continuous signal from discrete symbols.
            // 2. Wrap time modulo 2*UI.

            // Simplified interpolation for "Kids" app:
            // Just draw lines connecting p(i) to p(i+1) is jagged.
            // Let's do simple cosine interpolation for smoothness.
        }
    }

    // Improved Rendering Loop for discrete-time-like simulation
    // Since we don't have true oversampling from the channel model (DSP is simplified),
    // we artificially smooth the transition between samples to visualize the "analog" nature.

    const drawTrace = (y1: number, y2: number, y3: number) => {
       ctx.beginPath();
       // Drawing a curve from y1 (left) to y2 (center) to y3 (right)
       // We map this to 0 -> width.
       // Center (width/2) is y2. 
       // Left (0) is y1. Right (width) is y3.
       // We use quadratic curves.

       const x1 = 0;
       const x2 = width / 2;
       const x3 = width;

       const vy1 = offsetY - y1 * scaleY;
       const vy2 = offsetY - y2 * scaleY;
       const vy3 = offsetY - y3 * scaleY;

       ctx.moveTo(x1, vy1);
       // Control point for quadratic bezier? 
       // Catmull-Rom is better.
       // Let's just use many small line segments with cosine interpolation.

       for(let j=0; j<=samplesPerUI*2; j++) {
           const t = j / (samplesPerUI * 2); // 0 to 1 across 2 UIs
           const x = t * width;

           // Interpolating between y1, y2, y3.
           // t=0 -> y1. t=0.5 -> y2. t=1 -> y3.
           let y = 0;
           if (t < 0.5) {
               // Interp y1 to y2
               const localT = t * 2; // 0..1
               const mu2 = (1 - Math.cos(localT * Math.PI)) / 2;
               y = (y1 * (1 - mu2) + y2 * mu2);
           } else {
               // Interp y2 to y3
               const localT = (t - 0.5) * 2; // 0..1
               const mu2 = (1 - Math.cos(localT * Math.PI)) / 2;
               y = (y2 * (1 - mu2) + y3 * mu2);
           }

           ctx.lineTo(x, offsetY - y * scaleY);
       }
       ctx.stroke();
    };

    // Draw random subset of traces to keep performance high
    const stride = 2; // skip every other to save perf if needed
    const limit = Math.min(data.length - 2, 500); 

    for (let i = 0; i < limit; i+=stride) {
        // We align such that 'i' is the "center" symbol
        // We draw from i-1 to i+1
        if (i === 0) continue;
        drawTrace(data[i-1], data[i], data[i+1]);
    }

    // Draw Thresholds
    ctx.globalAlpha = 0.8;
    ctx.strokeStyle = '#f43f5e'; // Red
    ctx.setLineDash([5, 5]);
    ctx.lineWidth = 1;

    const drawHLine = (val: number) => {
        const y = offsetY - val * scaleY;
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(width, y);
        ctx.stroke();
    };

    drawHLine(0);
    if (pamType === PamType.PAM4) {
        drawHLine(2);
        drawHLine(-2);
    }
    ctx.setLineDash([]);

  }, [data, pamType, width, height]);

  return (
    <div className="relative bg-slate-900 rounded-lg border border-slate-700 p-2 shadow-xl">
       <h3 className="absolute top-2 left-4 text-xs font-bold text-slate-400 uppercase tracking-widest">{title}</h3>
      <canvas ref={canvasRef} width={width} height={height} className="rounded" />
      <div className="text-center text-xs text-slate-500 mt-1">Time (2 Unit Intervals)</div>
    </div>
  );
};

export default EyeDiagram;

import React from 'react';
import { LineChart, Line, XAxis, YAxis, ResponsiveContainer, Tooltip } from 'recharts';

interface OscilloscopeProps {
  data: number[];
  title: string;
  color: string;
}

const Oscilloscope: React.FC<OscilloscopeProps> = ({ data, title, color }) => {
  // Take last 50 points
  const chartData = data.slice(-50).map((val, idx) => ({ idx, val }));

  return (
    <div className="h-40 bg-slate-900 rounded-lg border border-slate-700 p-2 shadow-sm flex flex-col">
       <div className="flex justify-between items-center mb-1 px-2">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">{title}</h3>
            <span className="text-[10px] text-slate-600">Time Domain (Last 50 samples)</span>
       </div>
      <div className="flex-1 w-full">
        <ResponsiveContainer width="100%" height="100%">
          <LineChart data={chartData}>
            <YAxis domain={['auto', 'auto']} hide />
            <XAxis hide />
            <Tooltip 
                contentStyle={{backgroundColor: '#1e293b', border: 'none', borderRadius: '4px', fontSize: '12px'}}
                itemStyle={{color: color}}
                formatter={(val: number) => val.toFixed(2)}
                labelFormatter={() => ''}
            />
            <Line 
                type="monotone" 
                dataKey="val" 
                stroke={color} 
                strokeWidth={2} 
                dot={false} 
                isAnimationActive={false} 
            />
          </LineChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default Oscilloscope;

import React from 'react';
import { SimulationParams, PamType } from '../types';

interface ControlPanelProps {
  params: SimulationParams;
  setParams: React.Dispatch<React.SetStateAction<SimulationParams>>;
}

const ControlPanel: React.FC<ControlPanelProps> = ({ params, setParams }) => {

  const handleChannelChange = (idx: number, val: number) => {
    const newCh = [...params.channelResponse];
    newCh[idx] = val;
    setParams({ ...params, channelResponse: newCh });
  };

  const handleEqChange = (idx: number, val: number) => {
    const newEq = [...params.equalizerTaps];
    newEq[idx] = val;
    setParams({ ...params, equalizerTaps: newEq });
  };

  return (
    <div className="space-y-6 bg-slate-800 p-4 rounded-xl border border-slate-700 shadow-lg">

      {/* Mode Selection */}
      <div>
        <h3 className="text-sm font-bold text-slate-300 mb-2">Signal Mode</h3>
        <div className="flex gap-2">
          <button
            onClick={() => setParams(p => ({ ...p, pamType: PamType.PAM2 }))}
            className={`flex-1 py-2 rounded-md font-bold transition-all ${
              params.pamType === PamType.PAM2 
                ? 'bg-indigo-600 text-white shadow-indigo-500/50 shadow-lg scale-105' 
                : 'bg-slate-700 text-slate-400 hover:bg-slate-600'
            }`}
          >
            PAM-2 (NRZ)
          </button>
          <button
            onClick={() => setParams(p => ({ ...p, pamType: PamType.PAM4 }))}
             className={`flex-1 py-2 rounded-md font-bold transition-all ${
              params.pamType === PamType.PAM4 
                ? 'bg-pink-600 text-white shadow-pink-500/50 shadow-lg scale-105' 
                : 'bg-slate-700 text-slate-400 hover:bg-slate-600'
            }`}
          >
            PAM-4
          </button>
        </div>
      </div>

      {/* Noise Control */}
      <div>
        <div className="flex justify-between mb-1">
            <label className="text-sm font-medium text-slate-300">Noise Level (Jitter/Static)</label>
            <span className="text-xs text-indigo-400 font-mono">{params.noiseLevel.toFixed(3)}</span>
        </div>
        <input
          type="range"
          min="0"
          max="0.5"
          step="0.01"
          value={params.noiseLevel}
          onChange={(e) => setParams(p => ({ ...p, noiseLevel: parseFloat(e.target.value) }))}
          className="w-full h-2 bg-slate-600 rounded-lg appearance-none cursor-pointer accent-indigo-500"
        />
      </div>

      {/* Channel Editor */}
      <div>
        <div className="flex justify-between items-center mb-2">
             <label className="text-sm font-medium text-slate-300">Channel "Canyon" Profile</label>
             <div className="text-[10px] text-slate-500 bg-slate-900 px-2 py-1 rounded">Impulse Response H[n]</div>
        </div>
        <div className="flex gap-1 overflow-x-auto pb-2">
          {params.channelResponse.map((val, i) => (
            <div key={i} className="flex flex-col items-center">
              <div className="relative w-8 h-24 bg-slate-900 rounded flex items-end justify-center overflow-hidden border border-slate-600">
                <div 
                    style={{ height: `${Math.abs(val) * 80}%` }} 
                    className={`w-full ${val > 0 ? 'bg-emerald-500' : 'bg-red-500'} transition-all duration-300`}
                ></div>
              </div>
              <input
                type="number"
                step="0.1"
                value={val}
                onChange={(e) => handleChannelChange(i, parseFloat(e.target.value))}
                className="w-10 text-center text-xs bg-transparent text-slate-300 mt-1 border-b border-slate-600 focus:border-emerald-500 outline-none"
              />
            </div>
          ))}
          <button 
             onClick={() => setParams(p => ({ ...p, channelResponse: [...p.channelResponse, 0] }))}
             className="w-8 h-24 flex items-center justify-center text-slate-500 hover:text-emerald-400 border border-dashed border-slate-600 rounded hover:border-emerald-500 transition-colors"
          >
            +
          </button>
        </div>
      </div>

      {/* Equalizer Editor */}
      <div className={`transition-opacity duration-300 ${!params.useEqualizer ? 'opacity-50' : 'opacity-100'}`}>
        <div className="flex justify-between items-center mb-2">
             <div className="flex items-center gap-2">
                <input 
                    type="checkbox" 
                    checked={params.useEqualizer}
                    onChange={(e) => setParams(p => ({...p, useEqualizer: e.target.checked}))}
                    className="w-4 h-4 accent-cyan-500 rounded cursor-pointer"
                />
                <label className="text-sm font-medium text-slate-300 cursor-pointer" onClick={() => setParams(p => ({...p, useEqualizer: !p.useEqualizer}))}>Enable Equalizer (FFE)</label>
             </div>
        </div>

        <div className="flex gap-1 overflow-x-auto pb-2 pointer-events-auto">
          {params.equalizerTaps.map((val, i) => (
            <div key={i} className="flex flex-col items-center">
               <div className="relative w-8 h-24 bg-slate-900 rounded flex items-end justify-center overflow-hidden border border-slate-600">
                <div 
                    style={{ height: `${Math.min(Math.abs(val) * 50, 100)}%` }} 
                    className={`w-full ${val > 0 ? 'bg-cyan-500' : 'bg-orange-500'} transition-all duration-300`}
                ></div>
              </div>
              <input
                type="number"
                step="0.1"
                disabled={!params.useEqualizer}
                value={val}
                onChange={(e) => handleEqChange(i, parseFloat(e.target.value))}
                className="w-10 text-center text-xs bg-transparent text-slate-300 mt-1 border-b border-slate-600 focus:border-cyan-500 outline-none"
              />
            </div>
          ))}
           <button 
             disabled={!params.useEqualizer}
             onClick={() => setParams(p => ({ ...p, equalizerTaps: [...p.equalizerTaps, 0] }))}
             className="w-8 h-24 flex items-center justify-center text-slate-500 hover:text-cyan-400 border border-dashed border-slate-600 rounded hover:border-cyan-500 transition-colors"
          >
            +
          </button>
        </div>
      </div>

    </div>
  );
};

export default ControlPanel;

import React from 'react';
import { BlockDefinition } from '../types';
import { BLOCKS } from '../constants';

interface PipelineProps {
  onBlockClick: (block: BlockDefinition) => void;
  activeBlockId: string | null;
}

const Pipeline: React.FC<PipelineProps> = ({ onBlockClick, activeBlockId }) => {
  return (
    <div className="flex items-center justify-between w-full overflow-x-auto py-8 px-4 gap-4 no-scrollbar">
      {BLOCKS.map((block, index) => (
        <React.Fragment key={block.id}>
          <div 
            onClick={() => onBlockClick(block)}
            className={`
                relative flex-shrink-0 flex flex-col items-center justify-center 
                w-28 h-28 md:w-32 md:h-32 rounded-2xl cursor-pointer transition-all duration-300 transform hover:scale-105 border-2
                ${activeBlockId === block.id 
                    ? 'bg-indigo-900/50 border-indigo-400 shadow-[0_0_20px_rgba(99,102,241,0.5)]' 
                    : 'bg-slate-800 border-slate-700 hover:border-slate-500 shadow-lg'
                }
            `}
          >
            <div className="text-4xl md:text-5xl mb-2 animate-bounce-slow">{block.emoji}</div>
            <div className="text-xs font-bold text-center px-1 text-slate-200">{block.name}</div>

            {/* Connection Node */}
            <div className="absolute -right-3 top-1/2 w-4 h-4 bg-slate-600 rounded-full border-2 border-slate-900 z-10 hidden md:block"></div>
            {index !== 0 && <div className="absolute -left-3 top-1/2 w-4 h-4 bg-slate-600 rounded-full border-2 border-slate-900 z-10 hidden md:block"></div>}
          </div>

          {/* Arrow */}
          {index < BLOCKS.length - 1 && (
            <div className="flex-1 min-w-[20px] h-1 bg-slate-700 relative hidden md:block">
                <div className="absolute right-0 -top-1.5 w-0 h-0 border-t-[6px] border-t-transparent border-l-[10px] border-l-slate-700 border-b-[6px] border-b-transparent"></div>
            </div>
          )}
           {/* Mobile Down Arrow (simulated by gap in flex) */}
        </React.Fragment>
      ))}
    </div>
  );
};

export default Pipeline;

import React, { useState, useEffect } from 'react';
import { BlockDefinition } from '../types';
import { askProfessorSparky } from '../services/geminiService';

interface TutorModalProps {
  block: BlockDefinition | null;
  onClose: () => void;
