import React, { useState, useEffect, useMemo } from 'react';
import { DEFAULT_PARAMS } from './constants';
import { SimulationParams, BlockDefinition } from './types';
import { runSimulation } from './services/dsp';
import Pipeline from './components/Pipeline';
import ControlPanel from './components/ControlPanel';
import EyeDiagram from './components/EyeDiagram';
import Oscilloscope from './components/Oscilloscope';
import TutorModal from './components/TutorModal';

const App: React.FC = () => {
  const [params, setParams] = useState<SimulationParams>(DEFAULT_PARAMS);
  const [selectedBlock, setSelectedBlock] = useState<BlockDefinition | null>(null);

  // Memoize simulation result to avoid re-calc on pure renders, but depend on params
  const result = useMemo(() => runSimulation(params), [params]);

  // Generate context string for Gemini
  const contextString = `
    App is showing SerDes simulation.
    Mode: ${params.pamType}.
    Noise Level: ${params.noiseLevel}.
    Channel Response: [${params.channelResponse.join(', ')}].
    Equalizer Enabled: ${params.useEqualizer}.
    Current BER: ${result.ber.toFixed(5)}.
  `;

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-indigo-500 selection:text-white">

      {/* Navbar */}
      <header className="bg-slate-900 border-b border-slate-800 p-4 sticky top-0 z-30 shadow-lg backdrop-blur-md bg-opacity-80">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
            <div className="flex items-center gap-2">
                <span className="text-3xl">⚡</span>
                <h1 className="text-2xl font-black bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent">
                    SerDes Design <span className="text-slate-500 font-normal text-sm">for Kids</span>
                </h1>
            </div>

            <div className="flex items-center gap-4">
               <div className="hidden md:flex flex-col items-end">
                  <span className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Signal Quality (BER)</span>
                  <span className={`text-xl font-mono font-bold ${result.ber === 0 ? 'text-emerald-400' : result.ber < 1e-3 ? 'text-yellow-400' : 'text-red-500'}`}>
                    {result.ber === 0 ? "PERFECT" : result.ber.toFixed(4)}
                  </span>
               </div>
            </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-6 space-y-6">

        {/* Pipeline Visualizer */}
        <section>
             <h2 className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-2">The Data Pipeline (Click a block!)</h2>
            <Pipeline 
                onBlockClick={setSelectedBlock} 
                activeBlockId={selectedBlock?.id || null} 
            />
        </section>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

            {/* Left Column: Controls */}
            <div className="lg:col-span-4 space-y-6">
                <ControlPanel params={params} setParams={setParams} />

                {/* Real-time stats */}
                <div className="bg-slate-900 p-4 rounded-xl border border-slate-800">
                    <h3 className="text-sm font-bold text-slate-400 mb-3">Statistics</h3>
                    <div className="grid grid-cols-2 gap-4">
                        <div className="bg-slate-800 p-2 rounded">
                            <div className="text-xs text-slate-500">Bits Transmitted</div>
                            <div className="text-lg font-mono text-white">{result.bits.length}</div>
                        </div>
                        <div className="bg-slate-800 p-2 rounded">
                            <div className="text-xs text-slate-500">Error Count</div>
                            <div className="text-lg font-mono text-red-400">{Math.round(result.ber * result.bits.length)}</div>
                        </div>
                        <div className="bg-slate-800 p-2 rounded col-span-2">
                            <div className="text-xs text-slate-500">System Latency (Simulation)</div>
                            <div className="text-lg font-mono text-cyan-400">{(result.rxSignalRaw.length * 0.1).toFixed(1)} ps</div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Right Column: Visualizations */}
            <div className="lg:col-span-8 space-y-6">

                {/* Eye Diagrams Row */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <EyeDiagram 
                        data={result.rxSignalRaw} 
                        pamType={params.pamType} 
                        title="Before Equalizer (Messy)" 
                    />
                    <EyeDiagram 
                        data={result.rxSignalEq} 
                        pamType={params.pamType} 
                        title="After Equalizer (Clean?)" 
                    />
                </div>

                {/* Oscilloscopes Row */}
                <div className="grid grid-cols-1 gap-4">
                    <Oscilloscope 
                        data={result.rxSignalRaw} 
                        title="Channel Output (Raw Signal)" 
                        color="#f59e0b" // Amber
                    />
                     <Oscilloscope 
                        data={result.rxSignalEq} 
                        title="Receiver Input (After Filter)" 
                        color="#22d3ee" // Cyan
                    />
                </div>
            </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="mt-12 py-8 text-center text-slate-600 text-sm">
        <p>Built for future engineers 🚀</p>
      </footer>

      {/* Modals */}
      <TutorModal 
        block={selectedBlock} 
        onClose={() => setSelectedBlock(null)} 
        contextData={contextString}
      />

    </div>
  );
};

export default App;

