import React, { useState, useEffect, useRef } from 'react';
import { SimulationParams, PamType } from '../types';

interface ControlPanelProps {
  params: SimulationParams;
  setParams: React.Dispatch<React.SetStateAction<SimulationParams>>;
}

interface InteractiveTapProps {
    value: number;
    onChange: (v: number) => void;
    colorClass: string;
    disabled?: boolean;
}

// Sub-component for a single draggable bar
const InteractiveTap: React.FC<InteractiveTapProps> = ({ 
    value, 
    onChange, 
    colorClass,
    disabled = false
}) => {
    const [localText, setLocalText] = useState(value.toString());
    const containerRef = useRef<HTMLDivElement>(null);
    const isDragging = useRef(false);

    // Sync external changes to local text
    useEffect(() => {
        setLocalText(value.toFixed(2));
    }, [value]);

    const handleCommit = () => {
        let parsed = parseFloat(localText);
        if (isNaN(parsed)) {
             parsed = 0;
        }
        // Limit range roughly to prevent breaking sim
        if (parsed > 5) parsed = 5;
        if (parsed < -5) parsed = -5;

        onChange(parsed);
        setLocalText(parsed.toFixed(2));
    };

    const handlePointerDown = (e: React.PointerEvent) => {
        if (disabled) return;
        isDragging.current = true;
        (e.target as HTMLElement).setPointerCapture(e.pointerId);
        updateValueFromPointer(e);
    };

    const handlePointerMove = (e: React.PointerEvent) => {
        if (!isDragging.current || disabled) return;
        updateValueFromPointer(e);
    };

    const handlePointerUp = (e: React.PointerEvent) => {
        isDragging.current = false;
        (e.target as HTMLElement).releasePointerCapture(e.pointerId);
    };

    const updateValueFromPointer = (e: React.PointerEvent) => {
        if (!containerRef.current) return;
        const rect = containerRef.current.getBoundingClientRect();

        // Setup Range: +/- 1.5 is good for channel/EQ taps
        const RANGE = 1.5;

        // y: 0 at top, height at bottom.
        const relativeY = e.clientY - rect.top;
        const pct = 1 - (relativeY / rect.height); // 0 (bottom) to 1 (top)

        // Map 0..1 to -RANGE..+RANGE
        let newVal = (pct - 0.5) * 2 * RANGE;

        // Clamp
        if (newVal > RANGE) newVal = RANGE;
        if (newVal < -RANGE) newVal = -RANGE;

        // Snap to 0 if close
        if (Math.abs(newVal) < 0.05) newVal = 0;

        onChange(newVal);
    };

    const RANGE = 1.5;
    // Calculate visual height percentage relative to center
    const heightPct = Math.min((Math.abs(value) / RANGE) * 50, 50);
    const isPositive = value >= 0;

    return (
        <div className={`flex flex-col items-center gap-1 ${disabled ? 'opacity-40 grayscale pointer-events-none' : ''}`}>
             {/* Visual Bar Area */}
             <div 
                ref={containerRef}
                onPointerDown={handlePointerDown}
                onPointerMove={handlePointerMove}
                onPointerUp={handlePointerUp}
                className={`relative w-10 h-32 bg-slate-900 rounded border border-slate-600 overflow-hidden touch-none ${disabled ? '' : 'cursor-ns-resize hover:border-slate-400 hover:bg-slate-800 transition-colors'}`}
                title="Drag up/down to change value"
             >
                {/* Center Line (Zero) */}
                <div className="absolute top-1/2 left-0 w-full h-[1px] bg-slate-600 z-0 opacity-50"></div>

                {/* The Bar */}
                <div 
                    className={`absolute w-full z-10 ${colorClass} transition-all duration-75 ease-out`}
                    style={{
                        height: `${heightPct}%`,
                        [isPositive ? 'bottom' : 'top']: '50%',
                    }}
                ></div>
             </div>

             {/* Input */}
             <input
                type="text"
                disabled={disabled}
                value={localText}
                onChange={(e) => setLocalText(e.target.value)}
                onBlur={handleCommit}
                onKeyDown={(e) => { if (e.key === 'Enter') { handleCommit(); (e.target as HTMLInputElement).blur(); } }}
                className="w-12 text-center text-xs bg-transparent text-slate-300 border-b border-slate-600 focus:border-white outline-none focus:bg-slate-800 rounded-sm font-mono"
             />
        </div>
    )
};

