import React, { useState, useEffect, useRef } from 'react';
import { SimulationParams, PamType } from '../types';

interface ControlPanelProps {
  params: SimulationParams;
  setParams: React.Dispatch<React.SetStateAction<SimulationParams>>;
}

interface InteractiveTapProps {
    value: number;
    onChange: (v: number) => void;
    colorClass: string;
    disabled?: boolean;
}

// Sub-component for a single vertical fader
const InteractiveTap: React.FC<InteractiveTapProps> = ({ 
    value, 
    onChange, 
    colorClass,
    disabled = false
}) => {
    const [localText, setLocalText] = useState(value.toString());
    const containerRef = useRef<HTMLDivElement>(null);
    const isDragging = useRef(false);

    const MIN_VAL = -1.5;
    const MAX_VAL = 1.5;

    // Sync external changes to local text
    useEffect(() => {
        setLocalText(value.toFixed(2));
    }, [value]);

    const handleCommit = () => {
        let parsed = parseFloat(localText);
        if (isNaN(parsed)) {
             parsed = 0;
        }
        // Hard limit for simulation stability
        if (parsed > 5) parsed = 5;
        if (parsed < -5) parsed = -5;

        onChange(parsed);
        setLocalText(parsed.toFixed(2));
    };

    const updateValueFromPointer = (e: React.PointerEvent) => {
        if (!containerRef.current) return;
        const rect = containerRef.current.getBoundingClientRect();

        // Y coordinate relative to the container top
        const y = e.clientY - rect.top;
        const height = rect.height;

        // Map Y to Value: 
        // Top (0px) = MAX_VAL
        // Bottom (height) = MIN_VAL
        // Formula: val = Max - (y / height) * (Max - Min)

        let newVal = MAX_VAL - (y / height) * (MAX_VAL - MIN_VAL);

        // Clamp to visual range
        if (newVal > MAX_VAL) newVal = MAX_VAL;
        if (newVal < MIN_VAL) newVal = MIN_VAL;

        // Snap to zero for easier centered setting
        if (Math.abs(newVal) < 0.05) newVal = 0;

        onChange(newVal);
    };

    const handlePointerDown = (e: React.PointerEvent) => {
        if (disabled) return;
        isDragging.current = true;
        (e.target as HTMLElement).setPointerCapture(e.pointerId);
        updateValueFromPointer(e);
    };

    const handlePointerMove = (e: React.PointerEvent) => {
        if (!isDragging.current || disabled) return;
        updateValueFromPointer(e);
    };

    const handlePointerUp = (e: React.PointerEvent) => {
        isDragging.current = false;
        (e.target as HTMLElement).releasePointerCapture(e.pointerId);
    };

    // Calculate position percentages for UI
    // Normalize value to 0..1 range for CSS positioning
    // 1.0 = Max (Top), 0.0 = Min (Bottom)
    const normalizedVal = (value - MIN_VAL) / (MAX_VAL - MIN_VAL);
    const clampedNormalized = Math.max(0, Math.min(1, normalizedVal));
    const topPct = (1 - clampedNormalized) * 100;

    // For the fill bar (from center)
    const centerVal = (0 - MIN_VAL) / (MAX_VAL - MIN_VAL); // ~0.5
    const barTop = value > 0 ? topPct : centerVal * 100;
    const barHeight = Math.abs(normalizedVal - centerVal) * 100;

    return (
        <div className={`flex flex-col items-center gap-2 ${disabled ? 'opacity-40 grayscale pointer-events-none' : ''}`}>
             {/* Slider Track Area */}
             <div 
                ref={containerRef}
                onPointerDown={handlePointerDown}
                onPointerMove={handlePointerMove}
                onPointerUp={handlePointerUp}
                className={`relative w-8 h-32 flex justify-center touch-none select-none ${disabled ? '' : 'cursor-pointer group'}`}
                title="Drag to adjust"
             >
                {/* Background Track Groove */}
                <div className="absolute w-1.5 h-full bg-slate-900 rounded-full border border-slate-700/50"></div>

                {/* Center Tick Mark */}
                <div className="absolute top-1/2 w-4 h-[1px] bg-slate-600 z-0"></div>

                {/* Fill Bar (from 0 to value) */}
                <div 
                    className={`absolute w-1.5 rounded-full ${colorClass} transition-none`}
                    style={{
                        top: `${barTop}%`,
                        height: `${barHeight}%`
                    }}
                ></div>

                {/* Thumb Handle */}
                <div 
                    className="absolute w-5 h-5 bg-slate-200 rounded-full shadow-[0_2px_5px_rgba(0,0,0,0.5)] border-2 border-slate-400 z-10 transition-transform group-hover:scale-110"
                    style={{
                        top: `${topPct}%`,
                        transform: 'translateY(-50%)'
                    }}
                ></div>
             </div>

             {/* Value Input */}
             <input
                type="text"
                disabled={disabled}
                value={localText}
                onChange={(e) => setLocalText(e.target.value)}
                onBlur={handleCommit}
                onKeyDown={(e) => { if (e.key === 'Enter') { handleCommit(); (e.target as HTMLInputElement).blur(); } }}
                className="w-12 text-center text-[10px] bg-slate-900/50 text-slate-300 border border-slate-700 rounded focus:border-white outline-none focus:bg-slate-800 font-mono py-1"
             />
        </div>
    )
};

