import React, { useState, useEffect, useRef } from 'react';
import { SimulationParams, PamType } from '../types';

interface ControlPanelProps {
  params: SimulationParams;
  setParams: React.Dispatch<React.SetStateAction<SimulationParams>>;
}

interface InteractiveTapProps {
    value: number;
    onChange: (v: number) => void;
    active: boolean;
}

const InteractiveTap: React.FC<InteractiveTapProps> = ({ value, onChange, active }) => {
    const [localText, setLocalText] = useState(value.toString());
    const containerRef = useRef<HTMLDivElement>(null);
    const isDragging = useRef(false);

    const MIN_VAL = -1.0;
    const MAX_VAL = 1.0;

    useEffect(() => {
        setLocalText(value.toFixed(2));
    }, [value]);

    const handleCommit = () => {
        let parsed = parseFloat(localText);
        if (isNaN(parsed)) parsed = 0;
        if (parsed > 5) parsed = 5;
        if (parsed < -5) parsed = -5;
        onChange(parsed);
        setLocalText(parsed.toFixed(2));
    };

    const updateValue = (clientY: number) => {
        if (!containerRef.current) return;
        const rect = containerRef.current.getBoundingClientRect();
        const y = clientY - rect.top;
        const height = rect.height;
        let newVal = MAX_VAL - (y / height) * (MAX_VAL - MIN_VAL);
        if (newVal > MAX_VAL) newVal = MAX_VAL;
        if (newVal < MIN_VAL) newVal = MIN_VAL;
        if (Math.abs(newVal) < 0.05) newVal = 0;
        onChange(newVal);
    };

    const onPointerDown = (e: React.PointerEvent) => {
        if (!active) return;
        isDragging.current = true;
        (e.target as HTMLElement).setPointerCapture(e.pointerId);
        updateValue(e.clientY);
    };
    const onPointerMove = (e: React.PointerEvent) => {
        if (!isDragging.current || !active) return;
        updateValue(e.clientY);
    };
    const onPointerUp = (e: React.PointerEvent) => {
        isDragging.current = false;
        (e.target as HTMLElement).releasePointerCapture(e.pointerId);
    };

    // Visualization
    const range = MAX_VAL - MIN_VAL;
    const norm = (value - MIN_VAL) / range;
    const clampedNorm = Math.max(0, Math.min(1, norm));
    const thumbTopPct = (1 - clampedNorm) * 100;

    const zeroNorm = (0 - MIN_VAL) / range;
    const barTop = value > 0 ? thumbTopPct : zeroNorm * 100;
    const barHeight = Math.abs(norm - zeroNorm) * 100;

    return (
        <div className={`flex flex-col items-center gap-2 ${!active ? 'opacity-40 grayscale pointer-events-none' : ''}`}>
             <div 
                ref={containerRef}
                onPointerDown={onPointerDown}
                onPointerMove={onPointerMove}
                onPointerUp={onPointerUp}
                className="relative w-8 h-32 bg-gray-100 border border-gray-300 rounded-sm cursor-ns-resize hover:bg-gray-50 group"
             >
                {/* Center Line */}
                <div className="absolute top-1/2 left-0 w-full h-px bg-gray-300"></div>
                {/* Fill */}
                <div 
                    className="absolute w-full bg-blue-200/50"
                    style={{ top: `${barTop}%`, height: `${barHeight}%` }}
                ></div>
                {/* Thumb */}
                <div 
                    className="absolute left-0 w-full h-1 bg-blue-600 shadow-sm transition-transform group-hover:scale-x-110"
                    style={{ top: `${thumbTopPct}%`, transform: 'translateY(-50%)' }}
                ></div>
             </div>
             <input
                type="text"
                disabled={!active}
                value={localText}
                onChange={(e) => setLocalText(e.target.value)}
                onBlur={handleCommit}
                onKeyDown={(e) => { if (e.key === 'Enter') handleCommit(); }}
                className="w-12 text-center text-xs border border-gray-300 rounded-sm py-0.5 text-gray-700 focus:border-blue-500 outline-none"
             />
        </div>
    )
};

