import React, { useRef, useEffect } from 'react';
import { PamType } from '../types';

interface EyeDiagramProps {
  data: number[];
  pamType: PamType;
  width?: number;
  height?: number;
  title: string;
}

const EyeDiagram: React.FC<EyeDiagramProps> = ({ data, pamType, width = 300, height = 220, title }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Professional Lab Theme
    const BG_COLOR = '#ffffff';
    const GRID_COLOR = '#e2e8f0'; // Slate-200
    const AXIS_COLOR = '#94a3b8'; // Slate-400
    const TRACE_COLOR = '#2563eb'; // Blue-600
    const THRESHOLD_COLOR = '#ef4444'; // Red-500

    // Clear
    ctx.fillStyle = BG_COLOR;
    ctx.fillRect(0, 0, width, height);

    // Draw Grid (10 divisions horizontal, 8 vertical)
    ctx.strokeStyle = GRID_COLOR;
    ctx.lineWidth = 1;
    ctx.beginPath();

    // Vertical lines
    for (let i = 1; i < 10; i++) {
        const x = (width / 10) * i;
        ctx.moveTo(x, 0);
        ctx.lineTo(x, height);
    }
    // Horizontal lines
    for (let i = 1; i < 8; i++) {
        const y = (height / 8) * i;
        ctx.moveTo(0, y);
        ctx.lineTo(width, y);
    }
    ctx.stroke();

    // Center Axes
    ctx.strokeStyle = AXIS_COLOR;
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    ctx.moveTo(0, height / 2);
    ctx.lineTo(width, height / 2); // Time axis
    ctx.moveTo(width / 2, 0);
    ctx.lineTo(width / 2, height); // Voltage axis
    ctx.stroke();

    const samplesPerUI = 32; 
    const maxY = pamType === PamType.PAM4 ? 4.0 : 1.5; 
    const scaleY = (height / 2) / maxY;
    const offsetY = height / 2;

    ctx.strokeStyle = TRACE_COLOR;
    ctx.globalAlpha = 0.1; // Low alpha for accumulation effect
    ctx.lineWidth = 1.5;

    const drawTrace = (y1: number, y2: number, y3: number) => {
       ctx.beginPath();
       for(let j=0; j<=samplesPerUI*2; j++) {
           const t = j / (samplesPerUI * 2);
           const x = t * width;

           let y = 0;
           if (t < 0.5) {
               const localT = t * 2; 
               const mu2 = (1 - Math.cos(localT * Math.PI)) / 2;
               y = (y1 * (1 - mu2) + y2 * mu2);
           } else {
               const localT = (t - 0.5) * 2;
               const mu2 = (1 - Math.cos(localT * Math.PI)) / 2;
               y = (y2 * (1 - mu2) + y3 * mu2);
           }

           if (j === 0) ctx.moveTo(x, offsetY - y * scaleY);
           else ctx.lineTo(x, offsetY - y * scaleY);
       }
       ctx.stroke();
    };

    // Draw Traces
    const stride = 3; 
    const limit = Math.min(data.length - 2, 600); 

    for (let i = 1; i < limit; i+=stride) {
        drawTrace(data[i-1], data[i], data[i+1]);
    }

    // Thresholds
    ctx.globalAlpha = 1.0;
    ctx.strokeStyle = THRESHOLD_COLOR;
    ctx.setLineDash([4, 4]);
    ctx.lineWidth = 1;

    const drawHLine = (val: number) => {
        const y = offsetY - val * scaleY;
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(width, y);
        ctx.stroke();
    };

    drawHLine(0);
    if (pamType === PamType.PAM4) {
        drawHLine(2);
        drawHLine(-2);
    }
    ctx.setLineDash([]);

  }, [data, pamType, width, height]);

  return (
    <div className="bg-white border border-gray-200 rounded-sm shadow-sm overflow-hidden flex flex-col h-full">
      <div className="bg-gray-50 border-b border-gray-200 px-3 py-1 flex justify-between items-center">
         <h3 className="text-[10px] font-bold text-gray-700 uppercase tracking-wider">{title}</h3>
         <span className="text-[9px] text-gray-500">2.0 UI Window</span>
      </div>
      <div className="flex-1 relative bg-white">
        <canvas ref={canvasRef} width={width} height={height} className="w-full h-full block" />
      </div>
    </div>
  );
};

export default EyeDiagram;

