import React, { useRef, useEffect } from 'react';
import { PamType } from '../types';

interface EyeDiagramProps {
  data: number[];
  pamType: PamType;
  width?: number;
  height?: number;
  title: string;
}

const EyeDiagram: React.FC<EyeDiagramProps> = ({ data, pamType, width = 400, height = 300, title }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Professional Lab Theme
    const BG_COLOR = '#ffffff';
    const GRID_COLOR = '#e2e8f0'; // Slate-200
    const AXIS_COLOR = '#94a3b8'; // Slate-400
    const TRACE_COLOR = '#2563eb'; // Blue-600
    const THRESHOLD_COLOR = '#ef4444'; // Red-500

    // Clear
    ctx.clearRect(0, 0, width, height);
    ctx.fillStyle = BG_COLOR;
    ctx.fillRect(0, 0, width, height);

    // Draw Grid
    ctx.strokeStyle = GRID_COLOR;
    ctx.lineWidth = 1;
    ctx.beginPath();

    // Vertical lines (Time divisions)
    const vDivs = 8;
    for (let i = 1; i < vDivs; i++) {
        const x = (width / vDivs) * i;
        ctx.moveTo(x, 0);
        ctx.lineTo(x, height);
    }
    // Horizontal lines (Voltage divisions)
    const hDivs = 6;
    for (let i = 1; i < hDivs; i++) {
        const y = (height / hDivs) * i;
        ctx.moveTo(0, y);
        ctx.lineTo(width, y);
    }
    ctx.stroke();

    // Center Axes
    ctx.strokeStyle = AXIS_COLOR;
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    ctx.moveTo(0, height / 2);
    ctx.lineTo(width, height / 2); // Time axis (0V)
    ctx.moveTo(width / 2, 0);
    ctx.lineTo(width / 2, height); // Voltage axis (Center of Eye)
    ctx.stroke();

    // --- Auto-Scaling Logic ---
    // Calculate max amplitude to fit signal in view
    let maxAbs = 0;
    // Sample data to find peaks (optimization: check every nth sample)
    const step = Math.max(1, Math.floor(data.length / 1000));
    for(let i=0; i<data.length; i+=step) {
        const abs = Math.abs(data[i]);
        if(abs > maxAbs) maxAbs = abs;
    }

    // Define minimum vertical range to avoid zooming in on noise too much
    // PAM2 nominal is 1.0, PAM4 nominal is 3.0
    const minScale = pamType === PamType.PAM4 ? 3.5 : 1.5;
    const displayLimit = Math.max(maxAbs, minScale) * 1.2; // Add 20% headroom

    const scaleY = (height / 2) / displayLimit;
    const offsetY = height / 2;
    const samplesPerUI = 32; 

    // Draw Signal Traces
    ctx.strokeStyle = TRACE_COLOR;
    ctx.globalAlpha = 0.15; // Visibility of density
    ctx.lineWidth = 1.5;

    const drawTrace = (y1: number, y2: number, y3: number) => {
       ctx.beginPath();
       // Interpolate curve for smooth analog look
       // We draw from center of Left UI to center of Right UI (2 UI total width)
       // t=0 -> 0.5 (Left Eye), t=0.5 -> 1.0 (Right Eye)
       for(let j=0; j<=samplesPerUI*2; j++) {
           const t = j / (samplesPerUI * 2);
           const x = t * width;

           let yVal = 0;
           // Cosine interpolation
           if (t < 0.5) {
               const localT = t * 2; 
               const mu2 = (1 - Math.cos(localT * Math.PI)) / 2;
               yVal = (y1 * (1 - mu2) + y2 * mu2);
           } else {
               const localT = (t - 0.5) * 2;
               const mu2 = (1 - Math.cos(localT * Math.PI)) / 2;
               yVal = (y2 * (1 - mu2) + y3 * mu2);
           }

           const yPixel = offsetY - yVal * scaleY;

           if (j === 0) ctx.moveTo(x, yPixel);
           else ctx.lineTo(x, yPixel);
       }
       ctx.stroke();
    };

    // Render loop
    const stride = 5; // Skip some traces for performance
    const limit = Math.min(data.length - 2, 800); 

    for (let i = 1; i < limit; i+=stride) {
        drawTrace(data[i-1], data[i], data[i+1]);
    }

    // Draw Decision Thresholds
    ctx.globalAlpha = 1.0;
    ctx.strokeStyle = THRESHOLD_COLOR;
    ctx.setLineDash([4, 4]);
    ctx.lineWidth = 1;

    const drawHLine = (val: number) => {
        const y = offsetY - val * scaleY;
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(width, y);
        ctx.stroke();
    };

    // Draw 0V
    drawHLine(0);

    // Draw PAM4 intermediate thresholds
    if (pamType === PamType.PAM4) {
        drawHLine(2);
        drawHLine(-2);
    }
    ctx.setLineDash([]);

  }, [data, pamType, width, height]);

  return (
    <div className="bg-white border border-gray-200 rounded-sm shadow-sm overflow-hidden flex flex-col h-full">
      <div className="bg-gray-50 border-b border-gray-200 px-3 py-1 flex justify-between items-center shrink-0">
         <h3 className="text-[10px] font-bold text-gray-700 uppercase tracking-wider">{title}</h3>
         <span className="text-[9px] text-gray-500">2.0 UI Window</span>
      </div>
      <div className="flex-1 relative bg-white min-h-0">
        {/* Canvas scales to fit container */}
        <canvas ref={canvasRef} width={width} height={height} className="w-full h-full block" />
      </div>
    </div>
  );
};

export default EyeDiagram;

