import React, { useRef, useEffect } from 'react';
import { PamType } from '../types';

interface EyeDiagramProps {
  data: number[];
  pamType: PamType;
  width?: number;
  height?: number;
  title: string;
  isDark?: boolean;
}

const EyeDiagram: React.FC<EyeDiagramProps> = ({ data, pamType, width = 400, height = 300, title, isDark = false }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Theme Colors
    const BG_COLOR = isDark ? '#0f172a' : '#ffffff'; // Slate-900 vs White
    const GRID_COLOR = isDark ? '#1e293b' : '#e2e8f0'; // Slate-800 vs Slate-200
    const AXIS_COLOR = isDark ? '#475569' : '#94a3b8'; // Slate-600 vs Slate-400
    const TRACE_COLOR = isDark ? '#38bdf8' : '#2563eb'; // Sky-400 vs Blue-600
    const THRESHOLD_COLOR = isDark ? '#f87171' : '#ef4444'; // Red-400 vs Red-500

    // Clear
    ctx.clearRect(0, 0, width, height);
    ctx.fillStyle = BG_COLOR;
    ctx.fillRect(0, 0, width, height);

    // Draw Grid
    ctx.strokeStyle = GRID_COLOR;
    ctx.lineWidth = 1;
    ctx.beginPath();

    // Vertical lines (Time divisions)
    const vDivs = 8;
    for (let i = 1; i < vDivs; i++) {
        const x = (width / vDivs) * i;
        ctx.moveTo(x, 0);
        ctx.lineTo(x, height);
    }
    // Horizontal lines (Voltage divisions)
    const hDivs = 6;
    for (let i = 1; i < hDivs; i++) {
        const y = (height / hDivs) * i;
        ctx.moveTo(0, y);
        ctx.lineTo(width, y);
    }
    ctx.stroke();

    // Center Axes
    ctx.strokeStyle = AXIS_COLOR;
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    ctx.moveTo(0, height / 2);
    ctx.lineTo(width, height / 2); // Time axis (0V)
    ctx.moveTo(width / 2, 0);
    ctx.lineTo(width / 2, height); // Voltage axis (Center of Eye)
    ctx.stroke();

    // --- Auto-Scaling Logic ---
    let maxAbs = 0;
    const step = Math.max(1, Math.floor(data.length / 1000));
    for(let i=0; i<data.length; i+=step) {
        const abs = Math.abs(data[i]);
        if(abs > maxAbs) maxAbs = abs;
    }

    const minScale = pamType === PamType.PAM4 ? 3.5 : 1.5;
    const displayLimit = Math.max(maxAbs, minScale) * 1.2; 

    const scaleY = (height / 2) / displayLimit;
    const offsetY = height / 2;
    const samplesPerUI = 32; 

    // Draw Signal Traces
    ctx.strokeStyle = TRACE_COLOR;
    ctx.globalAlpha = isDark ? 0.2 : 0.15; // Slightly brighter density in dark mode
    ctx.lineWidth = 1.5;

    const drawTrace = (y1: number, y2: number, y3: number) => {
       ctx.beginPath();
       for(let j=0; j<=samplesPerUI*2; j++) {
           const t = j / (samplesPerUI * 2);
           const x = t * width;

           let yVal = 0;
           if (t < 0.5) {
               const localT = t * 2; 
               const mu2 = (1 - Math.cos(localT * Math.PI)) / 2;
               yVal = (y1 * (1 - mu2) + y2 * mu2);
           } else {
               const localT = (t - 0.5) * 2;
               const mu2 = (1 - Math.cos(localT * Math.PI)) / 2;
               yVal = (y2 * (1 - mu2) + y3 * mu2);
           }

           const yPixel = offsetY - yVal * scaleY;

           if (j === 0) ctx.moveTo(x, yPixel);
           else ctx.lineTo(x, yPixel);
       }
       ctx.stroke();
    };

    const stride = 5; 
    const limit = Math.min(data.length - 2, 800); 

    for (let i = 1; i < limit; i+=stride) {
        drawTrace(data[i-1], data[i], data[i+1]);
    }

    // Draw Decision Thresholds
    ctx.globalAlpha = 1.0;
    ctx.strokeStyle = THRESHOLD_COLOR;
    ctx.setLineDash([4, 4]);
    ctx.lineWidth = 1;

    const drawHLine = (val: number) => {
        const y = offsetY - val * scaleY;
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(width, y);
        ctx.stroke();
    };

    drawHLine(0);
    if (pamType === PamType.PAM4) {
        drawHLine(2);
        drawHLine(-2);
    }
    ctx.setLineDash([]);

  }, [data, pamType, width, height, isDark]);

  return (
    <div className="bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-sm shadow-sm overflow-hidden flex flex-col h-full transition-colors">
      <div className="bg-gray-50 dark:bg-slate-950 border-b border-gray-200 dark:border-slate-800 px-3 py-1 flex justify-between items-center shrink-0">
         <h3 className="text-[10px] font-bold text-gray-700 dark:text-slate-300 uppercase tracking-wider">{title}</h3>
         <span className="text-[9px] text-gray-500 dark:text-slate-500">2.0 UI Window</span>
      </div>
      <div className="flex-1 relative bg-white dark:bg-slate-900 min-h-0">
        <canvas ref={canvasRef} width={width} height={height} className="w-full h-full block" />
      </div>
    </div>
  );
};

