import React, { useState, useMemo, useEffect, useRef } from 'react';
import { DEFAULT_PARAMS } from './constants';
import { SimulationParams, BlockDefinition } from './types';
import { runSimulation } from './services/dsp';
import Pipeline from './components/Pipeline';
import ControlPanel from './components/ControlPanel';
import EyeDiagram from './components/EyeDiagram';
import Oscilloscope from './components/Oscilloscope';
import BathtubCurve from './components/BathtubCurve';
import PulseResponse from './components/PulseResponse';
import InfoModal, { HELP_TOPICS, HelpContent } from './components/InfoModal';

const App: React.FC = () => {
  const [params, setParams] = useState<SimulationParams>(DEFAULT_PARAMS);
  const [selectedBlockId, setSelectedBlockId] = useState<string | null>(null);
  const [helpContent, setHelpContent] = useState<HelpContent | null>(null);
  const [darkMode, setDarkMode] = useState(true);
  const [sidebarWidth, setSidebarWidth] = useState(400); // Wider default
  const sidebarRef = useRef<HTMLDivElement>(null);
  const isResizing = useRef(false);

  const result = useMemo(() => runSimulation(params), [params]);

  // Handle Theme Class on Body
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // Sidebar Resizing Logic
  const startResizing = (e: React.MouseEvent) => {
    isResizing.current = true;
    document.body.style.cursor = 'col-resize';
    document.body.style.userSelect = 'none';
  };

  const stopResizing = () => {
    isResizing.current = false;
    document.body.style.cursor = 'default';
    document.body.style.userSelect = 'auto';
  };

  const resize = (e: MouseEvent) => {
    if (isResizing.current) {
        // Clamp width between 280px and 600px
        let newWidth = e.clientX;
        if (newWidth < 280) newWidth = 280;
        if (newWidth > 600) newWidth = 600;
        setSidebarWidth(newWidth);
    }
  };

  useEffect(() => {
    window.addEventListener('mousemove', resize);
    window.addEventListener('mouseup', stopResizing);
    return () => {
      window.removeEventListener('mousemove', resize);
      window.removeEventListener('mouseup', stopResizing);
    };
  }, []);

  const handleBlockClick = (block: BlockDefinition) => {
      setSelectedBlockId(block.id);

      switch (block.id) {
          case 'gen':
              setHelpContent(HELP_TOPICS.MODULE_GEN);
              break;
          case 'tx':
              setHelpContent(HELP_TOPICS.MODULE_TX);
              break;
          case 'channel':
              setHelpContent(HELP_TOPICS.MODULE_CHANNEL);
              break;
          case 'rx_eq':
              setHelpContent(HELP_TOPICS.MODULE_RX_EQ);
              break;
          case 'rx_slicer':
              setHelpContent(HELP_TOPICS.MODULE_RX_SLICER);
              break;
          default:
              setHelpContent(null);
      }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans text-sm bg-gray-50 dark:bg-slate-950 transition-colors">

      {/* Professional Navbar */}
      <header className="bg-white dark:bg-slate-900 border-b border-gray-200 dark:border-slate-800 px-4 py-2 flex justify-between items-center shadow-sm z-20 sticky top-0 transition-colors">
        <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-blue-600 text-white flex items-center justify-center font-black rounded-sm shadow-lg shadow-blue-500/20">
                S
            </div>
            <div>
                <h1 className="text-lg font-bold text-gray-800 dark:text-slate-100 leading-tight">SerDes Designer <span className="text-blue-600 dark:text-blue-400">Pro</span></h1>
                <p className="text-[10px] text-gray-500 dark:text-slate-500 font-mono tracking-tight">V1.2.0 • SIGNAL INTEGRITY SIMULATOR</p>
            </div>
        </div>

        <div className="flex items-center gap-6">
           {/* Theme Toggle */}
           <button 
              onClick={() => setDarkMode(!darkMode)}
              className="p-1.5 rounded-full bg-gray-100 dark:bg-slate-800 text-gray-600 dark:text-slate-400 hover:bg-gray-200 dark:hover:bg-slate-700 transition-colors"
              title="Toggle Theme"
           >
              {darkMode ? (
                 <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" />
                 </svg>
              ) : (
                 <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" />
                 </svg>
              )}
           </button>

           <div className="flex flex-col items-end border-l border-gray-200 dark:border-slate-800 pl-6">
              <span className="text-[9px] text-gray-400 dark:text-slate-500 uppercase tracking-widest font-bold">Bit Error Rate</span>
              <span className={`text-xl font-mono font-bold ${result.ber < 1e-6 ? 'text-emerald-600 dark:text-emerald-400' : 'text-red-600 dark:text-red-400'}`}>
                {result.ber === 0 ? "< 1e-12" : result.ber.toExponential(2)}
              </span>
           </div>
        </div>
      </header>

      {/* Main Layout */}
      <main className="flex-1 flex flex-row overflow-hidden relative">

        {/* Left Sidebar: Controls */}
        <aside 
            ref={sidebarRef}
            className="border-r border-gray-200 dark:border-slate-800 bg-gray-50 dark:bg-slate-950 overflow-y-auto shrink-0 transition-colors"
            style={{ width: sidebarWidth }}
        >
            <div className="p-2 h-full">
                <ControlPanel params={params} setParams={setParams} width={sidebarWidth} />
            </div>
        </aside>

        {/* Resize Handle */}
        <div 
            onMouseDown={startResizing}
            className="w-1 cursor-col-resize bg-gray-200 dark:bg-slate-800 hover:bg-blue-400 dark:hover:bg-blue-600 transition-colors z-10"
        ></div>

        {/* Right Content */}
        <div className="flex-1 flex flex-col overflow-y-auto bg-gray-100 dark:bg-black/50 scrollbar-thin scrollbar-thumb-gray-300 dark:scrollbar-thumb-slate-700">

            {/* Top Flowchart */}
            <div className="shrink-0">
                <Pipeline onBlockClick={handleBlockClick} activeBlockId={selectedBlockId} />
            </div>

            {/* Dashboard Grid - Flex Grow Layout */}
            <div className="flex-1 flex flex-col p-3 gap-3 min-h-0">

                {/* Row 1: The Three Eyes (Flex 1) */}
                <div className="flex-1 min-h-[300px] grid grid-cols-1 md:grid-cols-3 gap-3">
                    <EyeDiagram 
                        data={result.txSymbols} 
                        pamType={params.pamType} 
                        title="TX Output (Source)"
                        isDark={darkMode}
                        onHelp={() => setHelpContent(HELP_TOPICS.EYE)}
                    />
                    <EyeDiagram 
                        data={result.rxSignalRaw} 
                        pamType={params.pamType} 
                        title="Channel Output (Distorted)" 
                        isDark={darkMode}
                        onHelp={() => setHelpContent(HELP_TOPICS.EYE)}
                    />
                    <EyeDiagram 
                        data={result.rxSignalEq} 
                        pamType={params.pamType} 
                        title="RX Input (Equalized)" 
                        isDark={darkMode}
                        onHelp={() => setHelpContent(HELP_TOPICS.EYE)}
                    />
                </div>

                {/* Row 2: Analysis Plots (Flex 1) */}
                <div className="flex-1 min-h-[300px] grid grid-cols-1 md:grid-cols-4 gap-3">
                    <div className="md:col-span-1">
                        <PulseResponse 
                            data={result.pulseResponse} 
                            isDark={darkMode} 
                            onHelp={() => setHelpContent(HELP_TOPICS.PULSE)}
                        />
                    </div>
                    <div className="md:col-span-1">
                        <BathtubCurve 
                            data={result.bathtubData} 
                            isDark={darkMode} 
                            onHelp={() => setHelpContent(HELP_TOPICS.BATHTUB)}
                        />
                    </div>
                    <div className="md:col-span-2">
                         <Oscilloscope 
                            data={result.rxSignalEq} 
                            title="Receiver Input (Transient)" 
                            color={darkMode ? "#0ea5e9" : "#0284c7"}
                            isDark={darkMode}
                            onHelp={() => setHelpContent(HELP_TOPICS.OSCILLOSCOPE)}
                        />
                    </div>
                </div>

            </div>
        </div>
      </main>

      {/* Replaced TutorModal with InfoModal */}
      <InfoModal 
         content={helpContent}
         onClose={() => {
            setHelpContent(null);
            setSelectedBlockId(null);
         }}
      />

    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';
import { PamType } from '../types';

interface EyeDiagramProps {
  data: number[];
  pamType: PamType;
  width?: number;
  height?: number;
  title: string;
  isDark?: boolean;
  onHelp?: () => void;
}

const EyeDiagram: React.FC<EyeDiagramProps> = ({ data, pamType, width = 400, height = 300, title, isDark = false, onHelp }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Dimensions with Margins for Labels
    const PAD_L = 35;
    const PAD_R = 10;
    const PAD_T = 10;
    const PAD_B = 20;
    const W = width - PAD_L - PAD_R;
    const H = height - PAD_T - PAD_B;

    // Theme Colors
    const BG_COLOR = isDark ? '#0f172a' : '#ffffff'; 
    const GRID_COLOR = isDark ? '#1e293b' : '#e2e8f0'; 
    const AXIS_COLOR = isDark ? '#475569' : '#94a3b8'; 
    const TRACE_COLOR = isDark ? '#38bdf8' : '#2563eb'; 
    const THRESHOLD_COLOR = isDark ? '#f87171' : '#ef4444'; 
    const TEXT_COLOR = isDark ? '#94a3b8' : '#64748b';

    // Clear and Background
    ctx.clearRect(0, 0, width, height);
    ctx.fillStyle = BG_COLOR;
    ctx.fillRect(0, 0, width, height);

    // --- Draw Grid ---
    ctx.strokeStyle = GRID_COLOR;
    ctx.lineWidth = 1;
    ctx.beginPath();

    // Vertical lines (Time divisions)
    const vDivs = 4; // 0, 0.5, 1.0, 1.5, 2.0 UI
    for (let i = 0; i <= vDivs; i++) {
        const x = PAD_L + (W / vDivs) * i;
        ctx.moveTo(x, PAD_T);
        ctx.lineTo(x, height - PAD_B);
    }
    // Horizontal lines (Voltage divisions)
    const hDivs = 4;
    for (let i = 0; i <= hDivs; i++) {
        const y = PAD_T + (H / hDivs) * i;
        ctx.moveTo(PAD_L, y);
        ctx.lineTo(width - PAD_R, y);
    }
    ctx.stroke();

    // --- Center Axes (Zero Lines) ---
    ctx.strokeStyle = AXIS_COLOR;
    ctx.lineWidth = 1.5;
    ctx.beginPath();

    // Horizontal Center (0V)
    const zeroY = PAD_T + H / 2;
    ctx.moveTo(PAD_L, zeroY);
    ctx.lineTo(width - PAD_R, zeroY); 

    // Vertical Center (1.0 UI - Middle of Eye)
    const centerX = PAD_L + W / 2;
    ctx.moveTo(centerX, PAD_T);
    ctx.lineTo(centerX, height - PAD_B); 
    ctx.stroke();

    // --- Auto-Scaling Logic ---
    let maxAbs = 0;
    const step = Math.max(1, Math.floor(data.length / 1000));
    for(let i=0; i<data.length; i+=step) {
        const abs = Math.abs(data[i]);
        if(abs > maxAbs) maxAbs = abs;
    }

    const minScale = pamType === PamType.PAM4 ? 3.5 : 1.5;
    const displayLimit = Math.max(maxAbs, minScale) * 1.1; 

    const scaleY = (H / 2) / displayLimit;

    // --- Draw Signal Traces ---
    const samplesPerUI = 32; 
    ctx.strokeStyle = TRACE_COLOR;
    ctx.globalAlpha = isDark ? 0.2 : 0.15;
    ctx.lineWidth = 1.5;

    const drawTrace = (y1: number, y2: number, y3: number) => {
       ctx.beginPath();
       for(let j=0; j<=samplesPerUI*2; j++) {
           const t = j / (samplesPerUI * 2); // 0 to 1 (representing 2 UI window)
           const x = PAD_L + t * W;

           let yVal = 0;
           if (t < 0.5) {
               const localT = t * 2; 
               const mu2 = (1 - Math.cos(localT * Math.PI)) / 2;
               yVal = (y1 * (1 - mu2) + y2 * mu2);
           } else {
               const localT = (t - 0.5) * 2;
               const mu2 = (1 - Math.cos(localT * Math.PI)) / 2;
               yVal = (y2 * (1 - mu2) + y3 * mu2);
           }

           const yPixel = zeroY - yVal * scaleY;

           if (j === 0) ctx.moveTo(x, yPixel);
           else ctx.lineTo(x, yPixel);
       }
       ctx.stroke();
    };

    const stride = 5; 
    const limit = Math.min(data.length - 2, 800); 

    for (let i = 1; i < limit; i+=stride) {
        drawTrace(data[i-1], data[i], data[i+1]);
    }

    // --- Draw Decision Thresholds ---
    ctx.globalAlpha = 1.0;
    ctx.strokeStyle = THRESHOLD_COLOR;
    ctx.setLineDash([4, 4]);
    ctx.lineWidth = 1;

    const drawHLine = (val: number) => {
        const y = zeroY - val * scaleY;
        ctx.beginPath();
        ctx.moveTo(PAD_L, y);
        ctx.lineTo(width - PAD_R, y);
        ctx.stroke();
    };

    drawHLine(0);
    if (pamType === PamType.PAM4) {
        drawHLine(2);
        drawHLine(-2);
    }
    ctx.setLineDash([]);

    // --- Draw Labels ---
    ctx.fillStyle = TEXT_COLOR;
    ctx.font = '10px sans-serif'; // Inter if loaded, else sans
    ctx.textAlign = 'right';
    ctx.textBaseline = 'middle';

    // Y Axis Labels
    const yTicks = 4;
    for(let i=0; i<=yTicks; i++) {
        // Map i (0..4) to (-limit .. +limit)
        const pct = i / yTicks; // 0..1
        const val = displayLimit - (pct * 2 * displayLimit); // +Lim to -Lim
        const y = PAD_T + (H * pct);
        ctx.fillText(val.toFixed(1), PAD_L - 4, y);
    }

    // X Axis Labels
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';
    const xTicks = 4; // 0, 0.5, 1.0, 1.5, 2.0
    for(let i=0; i<=xTicks; i++) {
        const uiVal = i * 0.5;
        const x = PAD_L + (W / xTicks) * i;
        ctx.fillText(uiVal.toFixed(1) + " UI", x, height - PAD_B + 4);
    }

  }, [data, pamType, width, height, isDark]);

  return (
    <div className="bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-sm shadow-sm overflow-hidden flex flex-col h-full transition-colors relative group">
      <div className="bg-gray-50 dark:bg-slate-950 border-b border-gray-200 dark:border-slate-800 px-3 py-1 flex justify-between items-center shrink-0">
         <h3 className="text-[10px] font-bold text-gray-700 dark:text-slate-300 uppercase tracking-wider">{title}</h3>
         <div className="flex items-center gap-2">
             <span className="text-[9px] text-gray-500 dark:text-slate-500">2.0 UI Window</span>
             {onHelp && (
                 <button 
                    onClick={onHelp}
                    className="w-4 h-4 rounded-full bg-gray-200 dark:bg-slate-800 text-gray-500 dark:text-slate-400 flex items-center justify-center hover:bg-blue-100 dark:hover:bg-blue-900 hover:text-blue-600 dark:hover:text-blue-400 transition-colors"
                    title="Explain this plot"
                 >
                    <span className="text-[10px] font-bold">?</span>
                 </button>
             )}
         </div>
      </div>
      <div className="flex-1 relative bg-white dark:bg-slate-900 min-h-0">
         {/* Use ResizeObserver logic ideally, but here we just fit to container roughly */}
        <canvas ref={canvasRef} width={width} height={height} className="w-full h-full block" />
      </div>
    </div>
  );
};

