            <div className="flex gap-1 overflow-x-auto pb-2 scrollbar-hide w-full">
            {params.channelResponse.map((val, i) => (
                <InteractiveTap key={`ch-${i}`} value={val} onChange={(v) => updateChannel(i, v)} active={true} />
            ))}
            <button 
                onClick={() => {
                    const arr = [...params.channelResponse, 0];
                    const newTaps = isAutoTune ? calculateZeroForcing(arr, params.equalizerTaps.length) : params.equalizerTaps;
