                className="w-8 h-32 flex items-center justify-center border border-dashed border-gray-300 dark:border-slate-700 rounded-sm text-gray-400 dark:text-slate-600 hover:border-blue-400 hover:text-blue-500 transition-colors flex-shrink-0 mb-[26px]"
            >
                +
            </button>
            </div>
          </div>
      </AccordionItem>

      {/* 4. RX Equalizer Accordion */}
