                <div className="bg-gray-50 dark:bg-slate-800/50 p-2 rounded border border-gray-100 dark:border-slate-800">
                    <div className="flex justify-between mb-1">
                        <label className="text-[9px] font-bold text-gray-600 dark:text-slate-400 uppercase">RJ (RMS)</label>
                        <span className="text-[9px] font-mono text-gray-500 dark:text-slate-500">{params.jitterRandom.toFixed(3)} UI</span>
                    </div>
                    <input
                        type="range"
                        min="0"
                        max="0.2"
                        step="0.005"
                        value={params.jitterRandom}
                        onChange={(e) => setParams(p => ({ ...p, jitterRandom: parseFloat(e.target.value) }))}
                        className="w-full h-1.5 bg-gray-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-600"
