                <div className="bg-gray-50 dark:bg-slate-800/50 p-2 rounded border border-gray-100 dark:border-slate-800">
                    <div className="flex justify-between mb-1">
                        <label className="text-[9px] font-bold text-gray-600 dark:text-slate-400 uppercase">DJ (Pk-Pk)</label>
                        <span className="text-[9px] font-mono text-gray-500 dark:text-slate-500">{params.jitterDeterministic.toFixed(3)} UI</span>
