import React, { useState, useMemo, useEffect, useRef } from 'react';
import { DEFAULT_PARAMS } from './constants';
import { SimulationParams, BlockDefinition } from './types';
import { runSimulation } from './services/dsp';
import Pipeline from './components/Pipeline';
import ControlPanel from './components/ControlPanel';
import EyeDiagram from './components/EyeDiagram';
import Oscilloscope from './components/Oscilloscope';
import BathtubCurve from './components/BathtubCurve';
import PulseResponse from './components/PulseResponse';
import InfoModal, { HELP_TOPICS, HelpContent } from './components/InfoModal';

const App: React.FC = () => {
  const [params, setParams] = useState<SimulationParams>(DEFAULT_PARAMS);
  const [selectedBlockId, setSelectedBlockId] = useState<string | null>(null);
  const [helpContent, setHelpContent] = useState<HelpContent | null>(null);
  const [darkMode, setDarkMode] = useState(true);
  const [sidebarWidth, setSidebarWidth] = useState(400); // Wider default
  const sidebarRef = useRef<HTMLDivElement>(null);
  const isResizing = useRef(false);

  const result = useMemo(() => runSimulation(params), [params]);

  // Handle Theme Class on Body
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // Sidebar Resizing Logic
  const startResizing = (e: React.MouseEvent) => {
    isResizing.current = true;
    document.body.style.cursor = 'col-resize';
    document.body.style.userSelect = 'none';
  };

  const stopResizing = () => {
    isResizing.current = false;
    document.body.style.cursor = 'default';
    document.body.style.userSelect = 'auto';
  };

  const resize = (e: MouseEvent) => {
    if (isResizing.current) {
        // Clamp width between 280px and 600px
        let newWidth = e.clientX;
        if (newWidth < 280) newWidth = 280;
        if (newWidth > 600) newWidth = 600;
        setSidebarWidth(newWidth);
    }
  };

  useEffect(() => {
    window.addEventListener('mousemove', resize);
    window.addEventListener('mouseup', stopResizing);
    return () => {
      window.removeEventListener('mousemove', resize);
      window.removeEventListener('mouseup', stopResizing);
    };
  }, []);

  const handleBlockClick = (block: BlockDefinition) => {
      setSelectedBlockId(block.id);

      switch (block.id) {
          case 'gen':
              setHelpContent(HELP_TOPICS.MODULE_GEN);
              break;
          case 'tx':
              setHelpContent(HELP_TOPICS.MODULE_TX); // Renamed in text to TX FIR
              break;
          case 'tx_dac':
              setHelpContent({
                  title: "TX DAC (Digital to Analog)",
                  body: (
                      <div className="space-y-3 text-sm text-gray-700 dark:text-gray-300">
                          <p>The <strong>DAC</strong> converts the digital numbers from the TX FIR filter into real analog voltages that drive the channel.</p>
                          <p>Ideally, it creates perfect steps. In reality, it has bandwidth limits and non-linearity.</p>
                      </div>
                  )
              });
              break;
          case 'channel':
              setHelpContent(HELP_TOPICS.MODULE_CHANNEL);
              break;
          case 'rx_adc':
               setHelpContent({
                  title: "RX ADC (Analog to Digital)",
                  body: (
                      <div className="space-y-3 text-sm text-gray-700 dark:text-gray-300">
                          <p>The <strong>ADC</strong> samples the continuous analog signal at specific time intervals and converts voltage levels into digital numbers.</p>
                          <p>Low resolution (fewer bits) introduces "Quantization Noise" which looks like jagged steps in the signal.</p>
                      </div>
                  )
              });
              break;
          case 'rx_eq':
              setHelpContent(HELP_TOPICS.MODULE_RX_EQ);
              break;
          case 'rx_dfe':
              setHelpContent(HELP_TOPICS.MODULE_RX_DFE);
              break;
          case 'rx_slicer':
              setHelpContent(HELP_TOPICS.MODULE_RX_SLICER);
              break;
          default:
              setHelpContent(null);
      }
  };

  const handleBerAnalysis = () => {
    const issues: React.ReactNode[] = [];

    // 1. Noise Check
    if (params.noiseLevel > 0.05) {
        issues.push(<li key="noise"><strong>High Noise Level:</strong> {params.noiseLevel.toFixed(3)}V is quite high. Try reducing Voltage Noise to &lt; 0.05V in the Channel settings.</li>);
    }

    // 2. Jitter Check
    if (params.jitterRandom > 0.1 || params.jitterDeterministic > 0.1) {
        issues.push(<li key="jitter"><strong>High Jitter:</strong> Your timing jitter is eating up the eye width. Try reducing RJ and DJ.</li>);
    }

    // 3. FFE Check
    if (!params.useEqualizer) {
        issues.push(<li key="ffe"><strong>FFE Disabled:</strong> The RX Linear Equalizer is off. Enable it to sharpen the edges.</li>);
    }

    // 4. DFE Check for ISI
    const hasLongChannel = params.channelResponse.length > 5;
    if (hasLongChannel && !params.useDfe) {
        issues.push(<li key="dfe"><strong>DFE Disabled:</strong> Your channel is long ({params.channelResponse.length} taps), causing significant ISI. Enable the DFE to cancel reflections.</li>);
    }

    // 5. Training Advice
    if (result.ber > 1e-4 && params.useEqualizer) {
        if (!params.useLms) {
             issues.push(<li key="train"><strong>Taps not Optimized:</strong> The equalizer taps might be static. Try clicking <strong>"Re-train (ZF)"</strong> or enabling <strong>"Adaptive LMS Mode"</strong>.</li>);
        } else if (params.useLms && !params.adaptDfe && params.useDfe) {
             issues.push(<li key="lms_dfe"><strong>Adapt DFE:</strong> FFE is adapting, but DFE is not. Try enabling <strong>"Adapt DFE Taps"</strong> to clean up residual noise.</li>);
        }
    }

    const content: HelpContent = {
        title: "BER Diagnostic Report",
        body: (
            <div className="space-y-4 text-sm text-gray-700 dark:text-gray-300">
                <div className={`p-4 rounded border ${result.ber < 1e-6 ? 'bg-green-50 border-green-200 dark:bg-green-900/20 dark:border-green-800' : 'bg-red-50 border-red-200 dark:bg-red-900/20 dark:border-red-800'}`}>
                    <div className="font-bold text-lg mb-1 flex items-center gap-2">
                        <span>Current BER:</span>
                        <span className="font-mono">{result.ber === 0 ? "< 1e-12" : result.ber.toExponential(2)}</span>
                    </div>
                    <p className="text-sm opacity-90">
                        {result.ber < 1e-6 
                            ? "Excellent signal quality! The link is stable." 
                            : "Signal quality is degraded. Errors are occurring."}
                    </p>
                </div>

                {issues.length > 0 ? (
                    <div>
                        <h4 className="font-bold text-gray-900 dark:text-white mb-2">Suggested Improvements:</h4>
                        <ul className="list-disc pl-5 space-y-2">
                            {issues}
                        </ul>
                    </div>
                ) : (
                    <p className="italic text-gray-500">No obvious configuration issues detected. If BER is still high, try tweaking the TX Pre-emphasis or adding more taps!</p>
                )}
            </div>
        )
    };

    setHelpContent(content);
  };

  return (
    <div className="h-screen flex flex-col font-sans text-sm bg-gray-50 dark:bg-slate-950 transition-colors overflow-hidden">

      {/* Professional Navbar */}
      <header className="bg-white dark:bg-slate-900 border-b border-gray-200 dark:border-slate-800 px-4 py-2 flex justify-between items-center shadow-sm z-20 shrink-0 transition-colors">
        <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-blue-600 text-white flex items-center justify-center font-black rounded-sm shadow-lg shadow-blue-500/20">
                S
            </div>
            <div>
                <h1 className="text-lg font-bold text-gray-800 dark:text-slate-100 leading-tight">SerDes Designer <span className="text-blue-600 dark:text-blue-400">Pro</span></h1>
                <p className="text-[10px] text-gray-500 dark:text-slate-500 font-mono tracking-tight">V1.3.0 • SIGNAL INTEGRITY SIMULATOR</p>
            </div>
        </div>

        <div className="flex items-center gap-6">
           {/* Theme Toggle */}
           <button 
              onClick={() => setDarkMode(!darkMode)}
              className="p-1.5 rounded-full bg-gray-100 dark:bg-slate-800 text-gray-600 dark:text-slate-400 hover:bg-gray-200 dark:hover:bg-slate-700 transition-colors"
              title="Toggle Theme"
           >
              {darkMode ? (
                 <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" />
                 </svg>
              ) : (
                 <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" />
                 </svg>
              )}
           </button>

           <div className="flex flex-col items-end border-l border-gray-200 dark:border-slate-800 pl-6">
              <div className="flex items-center gap-1.5">
                  <span className="text-[9px] text-gray-400 dark:text-slate-500 uppercase tracking-widest font-bold">Bit Error Rate</span>
                  <button 
                    onClick={handleBerAnalysis}
                    className="w-4 h-4 rounded-full bg-orange-100 dark:bg-orange-900/50 text-orange-600 dark:text-orange-400 flex items-center justify-center hover:scale-110 transition-transform cursor-pointer"
                    title="Analyze Signal Issues"
                  >
                      <span className="text-[10px] font-bold">?</span>
                  </button>
              </div>
              <span className={`text-xl font-mono font-bold ${result.ber < 1e-6 ? 'text-emerald-600 dark:text-emerald-400' : 'text-red-600 dark:text-red-400'}`}>
                {result.ber === 0 ? "< 1e-12" : result.ber.toExponential(2)}
              </span>
           </div>
        </div>
      </header>

      {/* Main Layout */}
      <main className="flex-1 flex flex-row overflow-hidden relative">

        {/* Left Sidebar: Controls */}
        <aside 
            ref={sidebarRef}
            className="border-r border-gray-200 dark:border-slate-800 bg-gray-50 dark:bg-slate-950 overflow-y-auto overflow-x-hidden shrink-0 transition-colors scrollbar-thin scrollbar-thumb-gray-300 dark:scrollbar-thumb-slate-700"
            style={{ width: sidebarWidth }}
        >
            <div className="p-2">
                <ControlPanel params={params} setParams={setParams} width={sidebarWidth} />
            </div>
        </aside>

        {/* Resize Handle */}
        <div 
            onMouseDown={startResizing}
            className="w-1 cursor-col-resize bg-gray-200 dark:bg-slate-800 hover:bg-blue-400 dark:hover:bg-blue-600 transition-colors z-10"
        ></div>

        {/* Right Content */}
        <div className="flex-1 flex flex-col overflow-hidden bg-gray-100 dark:bg-black/50">

            {/* Top Flowchart */}
            <div className="shrink-0">
                <Pipeline onBlockClick={handleBlockClick} activeBlockId={selectedBlockId} />
            </div>

            {/* Dashboard Grid - Flex Grow Layout */}
            <div className="flex-1 flex flex-col p-3 gap-3 min-h-0 overflow-hidden">

                {/* Row 1: The Four Eyes (2x2 on small, 4x1 on large) */}
                <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-3 min-h-0 flex-1">
                    <EyeDiagram 
                        data={result.txSymbols} 
                        pamType={params.pamType} 
                        title="1. TX Output (After FIR)"
                        isDark={darkMode}
                        onHelp={() => setHelpContent(HELP_TOPICS.EYE)}
                    />
                    <EyeDiagram 
                        data={result.rxSignalRaw} 
                        pamType={params.pamType} 
                        title="2. Channel Output" 
                        isDark={darkMode}
                        onHelp={() => setHelpContent(HELP_TOPICS.EYE)}
                    />
                    <EyeDiagram 
