import React, { useRef, useEffect, useState } from 'react';
import { PamType } from '../types';

interface EyeDiagramProps {
  data: number[];
  pamType: PamType;
  title: string;
  isDark?: boolean;
  onHelp?: () => void;
}

const EyeDiagram: React.FC<EyeDiagramProps> = ({ data, pamType, title, isDark = false, onHelp }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [dims, setDims] = useState({ width: 0, height: 0 });

  // Use ResizeObserver to handle fluid width/height
  useEffect(() => {
    if (!containerRef.current) return;

    const observer = new ResizeObserver((entries) => {
      const entry = entries[0];
      if (entry) {
        // Use devicePixelRatio for super sharp rendering on retina screens
        const dpr = window.devicePixelRatio || 1;
        setDims({
          width: entry.contentRect.width,
          height: entry.contentRect.height
        });
      }
    });

    observer.observe(containerRef.current);
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || dims.width === 0 || dims.height === 0) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const { width, height } = dims;

    // Dimensions with Margins
    const PAD_L = width < 150 ? 20 : 35; // Responsive padding
    const PAD_R = 10;
    const PAD_T = 10;
    const PAD_B = 20;
    const W = width - PAD_L - PAD_R;
    const H = height - PAD_T - PAD_B;

    // Theme Colors
    const BG_COLOR = isDark ? '#0f172a' : '#ffffff'; 
    const GRID_COLOR = isDark ? '#1e293b' : '#e2e8f0'; 
    const AXIS_COLOR = isDark ? '#475569' : '#94a3b8'; 
    const TRACE_COLOR = isDark ? '#38bdf8' : '#2563eb'; 
    const THRESHOLD_COLOR = isDark ? '#f87171' : '#ef4444'; 
    const TEXT_COLOR = isDark ? '#94a3b8' : '#64748b';

    // Clear and Background
    ctx.clearRect(0, 0, width, height);
    ctx.fillStyle = BG_COLOR;
    ctx.fillRect(0, 0, width, height);

    if (W <= 0 || H <= 0) return;

    // --- Draw Grid ---
    ctx.strokeStyle = GRID_COLOR;
    ctx.lineWidth = 1;
    ctx.beginPath();

    const vDivs = 4;
    for (let i = 0; i <= vDivs; i++) {
        const x = PAD_L + (W / vDivs) * i;
        ctx.moveTo(x, PAD_T);
        ctx.lineTo(x, height - PAD_B);
    }
    const hDivs = 4;
    for (let i = 0; i <= hDivs; i++) {
        const y = PAD_T + (H / hDivs) * i;
        ctx.moveTo(PAD_L, y);
        ctx.lineTo(width - PAD_R, y);
    }
    ctx.stroke();

    // --- Center Axes ---
    ctx.strokeStyle = AXIS_COLOR;
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    const zeroY = PAD_T + H / 2;
    ctx.moveTo(PAD_L, zeroY);
    ctx.lineTo(width - PAD_R, zeroY); 
    const centerX = PAD_L + W / 2;
    ctx.moveTo(centerX, PAD_T);
    ctx.lineTo(centerX, height - PAD_B); 
    ctx.stroke();

    // --- Auto-Scaling ---
    let maxAbs = 0;
    const dataSampleLimit = 1000;
    const step = Math.max(1, Math.floor(data.length / dataSampleLimit));
    for(let i=0; i<data.length; i+=step) {
        const abs = Math.abs(data[i]);
        if(abs > maxAbs) maxAbs = abs;
    }
    const minScale = pamType === PamType.PAM4 ? 3.5 : 1.5;
    const displayLimit = Math.max(maxAbs, minScale) * 1.1; 
    const scaleY = (H / 2) / displayLimit;

    // --- Draw Signal Traces ---
    const samplesPerUI = 32; 
    ctx.strokeStyle = TRACE_COLOR;
    ctx.globalAlpha = isDark ? 0.2 : 0.15;
    ctx.lineWidth = 1.2;

    const drawTrace = (y1: number, y2: number, y3: number) => {
       ctx.beginPath();
       for(let j=0; j<=samplesPerUI*2; j++) {
           const t = j / (samplesPerUI * 2);
           const x = PAD_L + t * W;
           let yVal = 0;
           if (t < 0.5) {
               const localT = t * 2; 
               const mu2 = (1 - Math.cos(localT * Math.PI)) / 2;
               yVal = (y1 * (1 - mu2) + y2 * mu2);
           } else {
               const localT = (t - 0.5) * 2;
               const mu2 = (1 - Math.cos(localT * Math.PI)) / 2;
               yVal = (y2 * (1 - mu2) + y3 * mu2);
           }
           const yPixel = zeroY - yVal * scaleY;
           if (j === 0) ctx.moveTo(x, yPixel);
           else ctx.lineTo(x, yPixel);
       }
       ctx.stroke();
    };

    const stride = 4; 
    const traceLimit = Math.min(data.length - 2, 600); 
    for (let i = 1; i < traceLimit; i+=stride) {
        drawTrace(data[i-1], data[i], data[i+1]);
    }

    // --- Draw Decision Thresholds ---
    ctx.globalAlpha = 1.0;
    ctx.strokeStyle = THRESHOLD_COLOR;
    ctx.setLineDash([3, 3]);
    ctx.lineWidth = 1;
    const drawHLine = (val: number) => {
        const y = zeroY - val * scaleY;
        ctx.beginPath();
        ctx.moveTo(PAD_L, y);
        ctx.lineTo(width - PAD_R, y);
        ctx.stroke();
    };
    drawHLine(0);
    if (pamType === PamType.PAM4) {
        drawHLine(2);
        drawHLine(-2);
    }
    ctx.setLineDash([]);

    // --- Draw Labels ---
    if (width > 120) {
        ctx.fillStyle = TEXT_COLOR;
        ctx.font = '9px sans-serif';
        ctx.textAlign = 'right';
        ctx.textBaseline = 'middle';
        // Y Axis Labels
        const yTicks = 2;
        for(let i=0; i<=yTicks; i++) {
            const pct = i / yTicks;
            const val = displayLimit - (pct * 2 * displayLimit);
            const y = PAD_T + (H * pct);
            ctx.fillText(val.toFixed(1), PAD_L - 4, y);
        }
        // X Axis Labels
        ctx.textAlign = 'center';
        ctx.textBaseline = 'top';
        const xTicks = 2;
        for(let i=0; i<=xTicks; i++) {
            const uiVal = i * 1.0;
            const x = PAD_L + (W / xTicks) * i;
            ctx.fillText(uiVal.toFixed(0) + "UI", x, height - PAD_B + 4);
        }
    }

  }, [data, pamType, dims, isDark]);

  return (
    <div className="bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-sm shadow-sm overflow-hidden flex flex-col h-full transition-colors relative group">
      <div className="bg-gray-50 dark:bg-slate-950 border-b border-gray-200 dark:border-slate-800 px-2 py-1 flex justify-between items-center shrink-0">
         <h3 className="text-[9px] font-bold text-gray-700 dark:text-slate-300 uppercase tracking-tight truncate mr-1">{title}</h3>
         <div className="flex items-center gap-1">
             {onHelp && (
                 <button 
                    onClick={onHelp}
                    className="w-3.5 h-3.5 rounded-full bg-gray-200 dark:bg-slate-800 text-gray-500 dark:text-slate-400 flex items-center justify-center hover:bg-blue-100 dark:hover:bg-blue-900 hover:text-blue-600 dark:hover:text-blue-400 transition-colors"
                 >
                    <span className="text-[8px] font-bold">?</span>
                 </button>
             )}
         </div>
      </div>
      <div ref={containerRef} className="flex-1 relative bg-white dark:bg-slate-900 min-h-0">
        <canvas 
            ref={canvasRef} 
            width={dims.width} 
            height={dims.height} 
            className="w-full h-full block" 
        />
      </div>
    </div>
  );
};

export default EyeDiagram;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { DEFAULT_PARAMS } from './constants';
import { SimulationParams, BlockDefinition, ActivityType } from './types';
import { runSimulation } from './services/dsp';
import Pipeline from './components/Pipeline';
import ControlPanel from './components/ControlPanel';
import EyeDiagram from './components/EyeDiagram';
import Oscilloscope from './components/Oscilloscope';
import BathtubCurve from './components/BathtubCurve';
import PulseResponse from './components/PulseResponse';
import InfoModal, { HELP_TOPICS, HelpContent } from './components/InfoModal';

const App: React.FC = () => {
  const [params, setParams] = useState<SimulationParams>(DEFAULT_PARAMS);
  const [selectedBlockId, setSelectedBlockId] = useState<string | null>(null);
  const [helpContent, setHelpContent] = useState<HelpContent | null>(null);
  const [darkMode, setDarkMode] = useState(true);
  const [sidebarWidth, setSidebarWidth] = useState(400);
  const [activeActivity, setActiveActivity] = useState<ActivityType | null>(ActivityType.MODULATION);

  const sidebarRef = useRef<HTMLDivElement>(null);
  const isResizing = useRef(false);

  const result = useMemo(() => runSimulation(params), [params]);

  // Handle Theme Class on Body
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // Sidebar Resizing Logic
  const startResizing = (e: React.MouseEvent) => {
    isResizing.current = true;
    document.body.style.cursor = 'col-resize';
    document.body.style.userSelect = 'none';
  };

  const stopResizing = () => {
    isResizing.current = false;
    document.body.style.cursor = 'default';
    document.body.style.userSelect = 'auto';
  };

  const resize = (e: MouseEvent) => {
    if (isResizing.current) {
        let newWidth = e.clientX - 64; // Offset for activity bar
        if (newWidth < 280) newWidth = 280;
        if (newWidth > 600) newWidth = 600;
        setSidebarWidth(newWidth);
    }
  };

  useEffect(() => {
    window.addEventListener('mousemove', resize);
    window.addEventListener('mouseup', stopResizing);
    return () => {
      window.removeEventListener('mousemove', resize);
      window.removeEventListener('mouseup', stopResizing);
    };
  }, []);

  const handleBlockClick = (block: BlockDefinition) => {
      setSelectedBlockId(block.id);

      switch (block.id) {
          case 'gen':
              setActiveActivity(ActivityType.MODULATION);
              setHelpContent(HELP_TOPICS.MODULE_GEN);
              break;
          case 'tx':
              setActiveActivity(ActivityType.TX_EQ);
              setHelpContent(HELP_TOPICS.MODULE_TX);
              break;
          case 'tx_dac':
              setActiveActivity(ActivityType.TX_EQ);
              setHelpContent({
                  title: "TX DAC (Digital to Analog)",
                  body: (
                      <div className="space-y-3 text-sm text-gray-700 dark:text-gray-300">
                          <p>The <strong>DAC</strong> converts the digital numbers from the TX FIR filter into real analog voltages that drive the channel.</p>
                          <p>Ideally, it creates perfect steps. In reality, it has bandwidth limits and non-linearity.</p>
                      </div>
                  )
              });
              break;
          case 'channel':
              setActiveActivity(ActivityType.CHANNEL);
              setHelpContent(HELP_TOPICS.MODULE_CHANNEL);
              break;
          case 'rx_adc':
               setActiveActivity(ActivityType.ADC);
               setHelpContent({
                  title: "RX ADC (Analog to Digital)",
                  body: (
                      <div className="space-y-3 text-sm text-gray-700 dark:text-gray-300">
                          <p>The <strong>ADC</strong> samples the continuous analog signal at specific time intervals and converts voltage levels into digital numbers.</p>
                          <p>Low resolution (fewer bits) introduces "Quantization Noise" which looks like jagged steps in the signal.</p>
                      </div>
                  )
              });
              break;
          case 'rx_eq':
              setActiveActivity(ActivityType.RX_EQ);
              setHelpContent(HELP_TOPICS.MODULE_RX_EQ);
              break;
          case 'rx_dfe':
              setActiveActivity(ActivityType.RX_DFE);
              setHelpContent(HELP_TOPICS.MODULE_RX_DFE);
              break;
          case 'rx_slicer':
              setHelpContent(HELP_TOPICS.MODULE_RX_SLICER);
              break;
          default:
              setHelpContent(null);
      }
  };

  const handleBerAnalysis = () => {
    const issues: React.ReactNode[] = [];
    if (params.noiseLevel > 0.05) issues.push(<li key="noise"><strong>High Noise Level:</strong> {params.noiseLevel.toFixed(3)}V is quite high. Reduce noise in <strong>Channel</strong>.</li>);
    if (params.jitterRandom > 0.1 || params.jitterDeterministic > 0.1) issues.push(<li key="jitter"><strong>High Jitter:</strong> Timing jitter is closing the eye horizontally. Adjust in <strong>Channel</strong>.</li>);
    if (!params.useEqualizer) issues.push(<li key="ffe"><strong>FFE Disabled:</strong> Enable the Linear Equalizer in <strong>RX FFE</strong> to sharpen edges.</li>);
    if (params.channelResponse.length > 5 && !params.useDfe) issues.push(<li key="dfe"><strong>DFE Disabled:</strong> Long channel ISI requires <strong>RX DFE</strong> to cancel post-cursors.</li>);

    const content: HelpContent = {
        title: "BER Diagnostic Report",
        body: (
            <div className="space-y-4 text-sm text-gray-700 dark:text-gray-300">
                <div className={`p-4 rounded border ${result.ber < 1e-6 ? 'bg-green-50 border-green-200 dark:bg-green-900/20 dark:border-green-800' : 'bg-red-50 border-red-200 dark:bg-red-900/20 dark:border-red-800'}`}>
                    <div className="font-bold text-lg mb-1 flex items-center gap-2">
                        <span>Current BER:</span>
                        <span className="font-mono">{result.ber === 0 ? "< 1e-12" : result.ber.toExponential(2)}</span>
                    </div>
                    <p className="text-sm opacity-90">{result.ber < 1e-6 ? "Excellent signal quality!" : "Signal quality is degraded."}</p>
                </div>
                {issues.length > 0 && (
                    <div>
                        <h4 className="font-bold text-gray-900 dark:text-white mb-2">Suggested Improvements:</h4>
                        <ul className="list-disc pl-5 space-y-2">{issues}</ul>
                    </div>
                )}
            </div>
        )
    };
    setHelpContent(content);
  };

  const activities = [
    { id: ActivityType.MODULATION, label: 'Modulation', icon: <path d="M3 12h4l3 8 4-16 3 8h4" /> },
    { id: ActivityType.TX_EQ, label: 'TX FIR', icon: <path d="M12 4v16m8-8H4" /> },
    { id: ActivityType.CHANNEL, label: 'Channel', icon: <path d="M13 2L3 14h9v8l10-12h-9l10-12z" /> },
    { id: ActivityType.ADC, label: 'ADC', icon: <path d="M3 21h18M3 18h15M3 15h12M3 12h9M3 9h6" /> },
    { id: ActivityType.RX_EQ, label: 'RX FFE', icon: <path d="M3 4h18l-9 12-9-12z" /> },
    { id: ActivityType.RX_DFE, label: 'RX DFE', icon: <path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /> },
  ];

  return (
    <div className="h-screen flex flex-col font-sans text-sm bg-gray-50 dark:bg-slate-950 transition-colors overflow-hidden">

      {/* Professional Navbar */}
      <header className="bg-white dark:bg-slate-900 border-b border-gray-200 dark:border-slate-800 px-4 py-2 flex justify-between items-center shadow-sm z-20 shrink-0 transition-colors">
        <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-blue-600 text-white flex items-center justify-center font-black rounded-sm shadow-lg shadow-blue-500/20">S</div>
            <div>
                <h1 className="text-lg font-bold text-gray-800 dark:text-slate-100 leading-tight">SerDes Designer <span className="text-blue-600 dark:text-blue-400">Pro</span></h1>
                <p className="text-[10px] text-gray-500 dark:text-slate-500 font-mono tracking-tight uppercase">V2.0.0 • Activity-Based Workflow</p>
            </div>
        </div>

        <div className="flex items-center gap-6">
           <button onClick={() => setDarkMode(!darkMode)} className="p-1.5 rounded-full bg-gray-100 dark:bg-slate-800 text-gray-600 dark:text-slate-400 hover:bg-gray-200 dark:hover:bg-slate-700 transition-colors">
              {darkMode ? <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" /></svg> : <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" /></svg>}
           </button>
           <div className="flex flex-col items-end border-l border-gray-200 dark:border-slate-800 pl-6">
              <div className="flex items-center gap-1.5">
                  <span className="text-[9px] text-gray-400 dark:text-slate-500 uppercase tracking-widest font-bold">Bit Error Rate</span>
                  <button onClick={handleBerAnalysis} className="w-4 h-4 rounded-full bg-orange-100 dark:bg-orange-900/50 text-orange-600 dark:text-orange-400 flex items-center justify-center hover:scale-110 transition-transform cursor-pointer"><span className="text-[10px] font-bold">?</span></button>
              </div>
              <span className={`text-xl font-mono font-bold ${result.ber < 1e-6 ? 'text-emerald-600 dark:text-emerald-400' : 'text-red-600 dark:text-red-400'}`}>
                {result.ber === 0 ? "< 1e-12" : result.ber.toExponential(2)}
              </span>
           </div>
        </div>
      </header>

      {/* Main Layout */}
      <main className="flex-1 flex flex-row overflow-hidden relative">

        {/* Activity Bar (Far Left) */}
        <nav className="w-16 bg-white dark:bg-slate-900 border-r border-gray-200 dark:border-slate-800 flex flex-col items-center py-4 gap-4 z-30 transition-colors">
            {activities.map(activity => (
                <button
                    key={activity.id}
                    onClick={() => {
                      if (activeActivity === activity.id) {
                        setActiveActivity(null);
                      } else {
                        setActiveActivity(activity.id);
                      }
                    }}
                    title={activity.label}
                    className={`
                        w-10 h-10 rounded-xl flex items-center justify-center transition-all duration-200
                        ${activeActivity === activity.id 
                            ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/30' 
                            : 'text-gray-400 dark:text-slate-600 hover:bg-gray-100 dark:hover:bg-slate-800 hover:text-gray-600 dark:hover:text-slate-300'}
                    `}
                >
                    <svg viewBox="0 0 24 24" className="w-5 h-5 fill-none stroke-current" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                        {activity.icon}
                    </svg>
                </button>
            ))}
        </nav>

        {/* Sidebar: Config Content - Conditionally rendered */}
        {activeActivity && (
          <>
            <aside 
                ref={sidebarRef}
                className="border-r border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-950 overflow-y-auto shrink-0 transition-colors"
                style={{ width: sidebarWidth }}
            >
                <ControlPanel params={params} setParams={setParams} activeActivity={activeActivity} />
            </aside>

            {/* Resize Handle */}
            <div onMouseDown={startResizing} className="w-1 cursor-col-resize bg-gray-100 dark:bg-slate-800 hover:bg-blue-400 dark:hover:bg-blue-600 transition-colors z-10"></div>
          </>
        )}

        {/* Right Content */}
        <div className="flex-1 flex flex-col overflow-hidden bg-gray-100 dark:bg-black/50">
            <div className="shrink-0">
                <Pipeline onBlockClick={handleBlockClick} activeBlockId={selectedBlockId} />
            </div>
            <div className="flex-1 flex flex-col p-3 gap-3 min-h-0 overflow-hidden">
                {/* Responsive Eye Diagram Grid: Focus on keeping columns in a single row */}
                <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 min-h-0 flex-1">
                    <EyeDiagram data={result.txSymbols} pamType={params.pamType} title="1. TX Output" isDark={darkMode} onHelp={() => setHelpContent(HELP_TOPICS.EYE)} />
                    <EyeDiagram data={result.rxSignalRaw} pamType={params.pamType} title="2. Channel Output" isDark={darkMode} onHelp={() => setHelpContent(HELP_TOPICS.EYE)} />
                    <EyeDiagram data={result.rxSignalEq} pamType={params.pamType} title="3. After RX FFE" isDark={darkMode} onHelp={() => setHelpContent(HELP_TOPICS.EYE)} />
                    <EyeDiagram data={result.rxSignalDfe} pamType={params.pamType} title="4. Final Receiver" isDark={darkMode} onHelp={() => setHelpContent(HELP_TOPICS.EYE)} />
                </div>
                <div className="flex-1 min-h-0 grid grid-cols-1 md:grid-cols-4 gap-3">
                    <div className="md:col-span-1 min-h-0"><PulseResponse data={result.pulseResponse} isDark={darkMode} onHelp={() => setHelpContent(HELP_TOPICS.PULSE)} /></div>
                    <div className="md:col-span-1 min-h-0"><BathtubCurve data={result.bathtubData} isDark={darkMode} onHelp={() => setHelpContent(HELP_TOPICS.BATHTUB)} /></div>
                    <div className="md:col-span-2 min-h-0"><Oscilloscope data={result.rxSignalDfe} title="Receiver Decision Input (Transient)" color={darkMode ? "#0ea5e9" : "#0284c7"} isDark={darkMode} onHelp={() => setHelpContent(HELP_TOPICS.OSCILLOSCOPE)} /></div>
                </div>
            </div>
        </div>
      </main>

      <InfoModal content={helpContent} onClose={() => { setHelpContent(null); setSelectedBlockId(null); }} />
    </div>
  );
};

export default App;

import { PamType, SimulationParams, BlockDefinition } from './types';

export const DEFAULT_PARAMS: SimulationParams = {
  pamType: PamType.PAM2,
  dataRateGbps: 10,
  channelResponse: [0.05, 0.8, 0.4, 0.1, 0.05, 0.0, -0.05], // More realistic ISI
  equalizerTaps: [0.0, 1.0, 0.0], // RX Pass-through initially
  txEqualizerTaps: [0.0, 1.0, -0.2], // TX Pre-emphasis default
  dfeTaps: [0.0], // DFE disabled by default

  // Impairments defaults
  noiseLevel: 0.015, // 15mV RMS
  jitterRandom: 0.02, // 0.02 UI RMS
  jitterDeterministic: 0.00, // 0 UI
  adcBits: 0, // 0 means Ideal (Infinite precision)

  useEqualizer: true,
  useLms: false,
  adaptDfe: false, // Default to separate training (FFE only first)
  lmsStepSize: 0.01,

  useTxEqualizer: true,
  useDfe: true,
};

