  // TX FIR: Pre-emphasized Pulse (Stepped/Shaped)
  WAVE: "M2 16 h3 v-4 h3 v-5 h8 v5 h3 v4 h3",

  // Channel: Input Pulse vs Output Response (Degradation)
  RESISTOR: "M2 16h2v-8h4v8h2 M14 16h2c0-8 4-8 4 0h2",

  // RX FFE: Tapped Delay Line Representation
  FILTER: "M2 12h2 M4 7h4v10h-4z M8 12h2 M10 7h4v10h-4z M14 12h2 M16 7h4v10h-4z M20 12h2",

